import type { FastifyInstance } from "fastify";
import { getPool } from "../config/database.js";
import { verificarAuth } from "../middleware/auth.js";
import { exigirServidor } from "../middleware/autorizacao.js";
import { tratarErro } from "../utils/erros.js";
import { cacheGet, cacheSet, cacheInvalidar, CACHE_TTL, CACHE_KEY } from "../config/cache.js";

export async function rotasServidores(app: FastifyInstance) {
  app.addHook("preHandler", verificarAuth);
  app.addHook("preHandler", exigirServidor);

  // GET /api/servidores/me ÔÇö retorna servidor do usu├írio logado
  app.get("/api/servidores/me", async (req, reply) => {
    try {
      const servidor = req.usuario!.servidor;
      if (!servidor) return reply.status(404).send({ error: "Servidor n├úo encontrado" });
      // Buscar com joins completos
      const { rows } = await getPool().query(
        `SELECT s.id, s.nome, s.email, s.cpf, s.telefone, s.cargo,
                s.perfil_id, s.secretaria_id, s.user_id, s.data_nascimento,
                s.criado_em, s.atualizado_em, s.is_superadmin,
                json_build_object('id', p.id, 'nome', p.nome, 'descricao', p.descricao, 'permissoes', p.permissoes) AS perfil,
                json_build_object('id', sec.id, 'nome', sec.nome, 'sigla', sec.sigla, 'municipio_id', sec.municipio_id, 'ativo', sec.ativo) AS secretaria
         FROM servidores s
         JOIN perfis p ON s.perfil_id = p.id
         JOIN secretarias sec ON s.secretaria_id = sec.id
         WHERE s.id = $1`,
        [servidor.id],
      );
      const data = rows[0];
      // N├úo retornar is_superadmin para n├úo-superadmins
      if (data && !data.is_superadmin) {
        delete data.is_superadmin;
      }
      reply.send({ data });
    } catch (e) { tratarErro(e, reply); }
  });

  // GET /api/servidores
  app.get("/api/servidores", async (req, reply) => {
    try {
      const { secretaria_id } = req.query as { secretaria_id?: string };
      const params: unknown[] = [];
      let sql = `
        SELECT s.*, p.nome AS perfil_nome, p.descricao AS perfil_descricao,
               sec.nome AS secretaria_nome, sec.sigla AS secretaria_sigla
        FROM servidores s
        JOIN perfis p ON s.perfil_id = p.id
        JOIN secretarias sec ON s.secretaria_id = sec.id
        WHERE s.deletado_em IS NULL`;

      if (secretaria_id) {
        params.push(secretaria_id);
        sql += ` AND s.secretaria_id = $${params.length}`;
      }

      // Filtro por munic├¡pio (ex-RLS)
      params.push(req.usuario!.servidor!.municipio_id);
      sql += ` AND sec.municipio_id = $${params.length}`;
      sql += ` ORDER BY s.nome`;

      const { rows } = await getPool().query(sql, params);
      reply.send({ data: rows });
    } catch (e) { tratarErro(e, reply); }
  });

  // GET /api/servidores/:id
  app.get("/api/servidores/:id", async (req, reply) => {
    try {
      const { id } = req.params as { id: string };
      const { rows } = await getPool().query(
        `SELECT s.*, p.nome AS perfil_nome, p.descricao AS perfil_descricao,
                sec.nome AS secretaria_nome, sec.sigla AS secretaria_sigla
         FROM servidores s
         JOIN perfis p ON s.perfil_id = p.id
         JOIN secretarias sec ON s.secretaria_id = sec.id
         WHERE s.id = $1 AND s.deletado_em IS NULL AND sec.municipio_id = $2`,
        [id, req.usuario!.servidor!.municipio_id],
      );
      if (!rows[0]) return reply.status(404).send({ error: "Servidor n├úo encontrado" });
      reply.send({ data: rows[0] });
    } catch (e) { tratarErro(e, reply); }
  });

  // POST /api/servidores
  app.post("/api/servidores", async (req, reply) => {
    try {
      const body = req.body as {
        nome: string; email: string; cpf?: string; matricula?: string;
        perfil_id: string; secretaria_id: string; telefone?: string;
      };
      const { rows } = await getPool().query(
        `INSERT INTO servidores (nome, email, cpf, matricula, perfil_id, secretaria_id, telefone)
         VALUES ($1, $2, $3, $4, $5, $6, $7) RETURNING *`,
        [body.nome, body.email, body.cpf, body.matricula, body.perfil_id, body.secretaria_id, body.telefone],
      );
      reply.status(201).send({ data: rows[0] });
    } catch (e) { tratarErro(e, reply); }
  });

  // PUT /api/servidores/:id
  app.put("/api/servidores/:id", async (req, reply) => {
    try {
      const { id } = req.params as { id: string };
      const body = req.body as Record<string, unknown>;
      const campos = ["nome", "email", "cpf", "matricula", "perfil_id", "secretaria_id", "telefone"];
      const sets: string[] = [];
      const params: unknown[] = [];
      for (const c of campos) {
        if (body[c] !== undefined) {
          params.push(body[c]);
          sets.push(`${c} = $${params.length}`);
        }
      }
      if (sets.length === 0) return reply.status(400).send({ error: "Nenhum campo para atualizar" });
      params.push(new Date().toISOString());
      sets.push(`atualizado_em = $${params.length}`);
      params.push(id);
      const { rows } = await getPool().query(
        `UPDATE servidores SET ${sets.join(", ")} WHERE id = $${params.length} RETURNING *`,
        params,
      );
      if (!rows[0]) return reply.status(404).send({ error: "Servidor n├úo encontrado" });
      reply.send({ data: rows[0] });
    } catch (e) { tratarErro(e, reply); }
  });

  // DELETE /api/servidores/:id (soft delete)
  app.delete("/api/servidores/:id", async (req, reply) => {
    try {
      const { id } = req.params as { id: string };
      await getPool().query(
        `UPDATE servidores SET deletado_em = NOW(), atualizado_em = NOW() WHERE id = $1`,
        [id],
      );
      reply.status(204).send();
    } catch (e) { tratarErro(e, reply); }
  });

  // GET /api/perfis
  app.get("/api/perfis", async (_req, reply) => {
    try {
      const cached = await cacheGet(CACHE_KEY.PERFIS);
      if (cached) return reply.send({ data: cached });
      const { rows } = await getPool().query(`SELECT * FROM perfis ORDER BY nome`);
      await cacheSet(CACHE_KEY.PERFIS, rows, CACHE_TTL.PERFIS);
      reply.send({ data: rows });
    } catch (e) { tratarErro(e, reply); }
  });

  // GET /api/secretarias
  app.get("/api/secretarias", async (req, reply) => {
    try {
      const municipioId = req.usuario!.servidor!.municipio_id;
      const { rows } = await getPool().query(
        `SELECT * FROM secretarias WHERE municipio_id = $1 AND deletado_em IS NULL ORDER BY nome`,
        [municipioId],
      );
      reply.send({ data: rows });
    } catch (e) { tratarErro(e, reply); }
  });

  // POST /api/secretarias
  app.post("/api/secretarias", async (req, reply) => {
    try {
      const body = req.body as { nome: string; sigla?: string; municipio_id: string };
      const { rows } = await getPool().query(
        `INSERT INTO secretarias (nome, sigla, municipio_id) VALUES ($1, $2, $3) RETURNING *`,
        [body.nome, body.sigla, body.municipio_id],
      );
      reply.status(201).send({ data: rows[0] });
    } catch (e) { tratarErro(e, reply); }
  });

  // PUT /api/secretarias/:id
  app.put("/api/secretarias/:id", async (req, reply) => {
    try {
      const { id } = req.params as { id: string };
      const body = req.body as { nome?: string; sigla?: string };
      const sets: string[] = [];
      const params: unknown[] = [];
      if (body.nome) { params.push(body.nome); sets.push(`nome = $${params.length}`); }
      if (body.sigla !== undefined) { params.push(body.sigla); sets.push(`sigla = $${params.length}`); }
      params.push(new Date().toISOString()); sets.push(`atualizado_em = $${params.length}`);
      params.push(id);
      const { rows } = await getPool().query(
        `UPDATE secretarias SET ${sets.join(", ")} WHERE id = $${params.length} RETURNING *`, params,
      );
      reply.send({ data: rows[0] });
    } catch (e) { tratarErro(e, reply); }
  });
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
// Dead-Letter Queue para Auditoria ÔÇö Fase 12.1
// Garante que nenhum registro de auditoria seja perdido silenciosamente.
// Usa Redis como fila de retry com exponential backoff (3 tentativas).
// Ap├│s 3 falhas, alerta o administrador e persiste em fallback local.
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import { getPool } from "../config/database.js";
import { getRedis } from "../config/cache.js";

const AUDIT_DLQ_KEY = "audit:dlq";
const AUDIT_DLQ_PROCESSING = "audit:dlq:processing";
const MAX_RETRIES = 3;
const BACKOFF_BASE_MS = 1000; // 1s, 2s, 4s

interface AuditEntry {
  servidor_id?: string | null;
  municipio_id?: string | null;
  acao: string;
  tabela?: string | null;
  registro_id?: string | null;
  dados_anteriores?: unknown;
  dados_novos?: unknown;
  ip_address?: string | null;
  user_agent?: string | null;
  _retries?: number;
  _first_failed_at?: string;
}

// ÔöÇÔöÇ Fallback local quando Redis tamb├®m est├í offline ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const localFallbackQueue: AuditEntry[] = [];

/**
 * Registrar evento de auditoria com garantia de entrega.
 * Se o INSERT falhar, enfileira para retry autom├ítico.
 */
export async function registrarAuditoria(entry: AuditEntry): Promise<void> {
  try {
    await inserirAuditLog(entry);
  } catch (err) {
    console.warn("[audit-dlq] INSERT falhou, enfileirando para retry:", (err as Error).message);
    await enfileirar({ ...entry, _retries: 0, _first_failed_at: new Date().toISOString() });
  }
}

/**
 * INSERT direto no audit_log.
 */
async function inserirAuditLog(entry: AuditEntry): Promise<void> {
  await getPool().query(
    `INSERT INTO audit_log (servidor_id, municipio_id, acao, tabela, registro_id, dados_anteriores, dados_novos, ip_address, user_agent)
     VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)`,
    [
      entry.servidor_id ?? null,
      entry.municipio_id ?? null,
      entry.acao,
      entry.tabela ?? null,
      entry.registro_id ?? null,
      entry.dados_anteriores ? JSON.stringify(entry.dados_anteriores) : null,
      entry.dados_novos ? JSON.stringify(entry.dados_novos) : null,
      entry.ip_address ?? null,
      entry.user_agent ?? null,
    ],
  );
}

/**
 * Enfileirar entrada para retry (Redis ou fallback local).
 */
async function enfileirar(entry: AuditEntry): Promise<void> {
  const redis = getRedis();
  if (redis) {
    try {
      await redis.rPush(AUDIT_DLQ_KEY, JSON.stringify(entry));
      return;
    } catch {
      // Redis tamb├®m falhou ÔÇö fallback local
    }
  }
  localFallbackQueue.push(entry);
  console.warn(`[audit-dlq] Redis indispon├¡vel ÔÇö fallback local (${localFallbackQueue.length} pending)`);
}

/**
 * Processar fila de retry. Chamado periodicamente (setInterval).
 * Usa exponential backoff: 1s, 2s, 4s entre tentativas.
 */
export async function processarFilaAuditoria(): Promise<{ processados: number; falhas: number }> {
  let processados = 0;
  let falhas = 0;

  // 1) Processar fallback local primeiro
  while (localFallbackQueue.length > 0) {
    const entry = localFallbackQueue[0];
    try {
      await inserirAuditLog(entry);
      localFallbackQueue.shift();
      processados++;
    } catch {
      // Tentar enfileirar no Redis agora
      const redis = getRedis();
      if (redis) {
        try {
          await redis.rPush(AUDIT_DLQ_KEY, JSON.stringify(entry));
          localFallbackQueue.shift();
        } catch {
          break; // Ambos offline, parar
        }
      } else {
        break;
      }
    }
  }

  // 2) Processar fila Redis
  const redis = getRedis();
  if (!redis) return { processados, falhas };

  const batchSize = 50;
  for (let i = 0; i < batchSize; i++) {
    const raw = await redis.lPop(AUDIT_DLQ_KEY);
    if (!raw) break;

    let entry: AuditEntry;
    try {
      entry = JSON.parse(raw) as AuditEntry;
    } catch {
      falhas++;
      continue;
    }

    try {
      await inserirAuditLog(entry);
      processados++;
    } catch (err) {
      const retries = (entry._retries ?? 0) + 1;
      entry._retries = retries;

      if (retries >= MAX_RETRIES) {
        // M├íximo de tentativas atingido ÔÇö alertar administrador
        falhas++;
        await alertarFalhaAuditoria(entry, err as Error);
        // Mover para fila de mortos (nunca perder)
        try {
          await redis.rPush("audit:dead", JSON.stringify(entry));
        } catch {
          console.error("[audit-dlq] FALHA CR├ìTICA: imposs├¡vel persistir audit entry:", JSON.stringify(entry));
        }
      } else {
        // Re-enfileirar com delay (backoff calculado no processamento)
        try {
          await redis.rPush(AUDIT_DLQ_PROCESSING, JSON.stringify(entry));
        } catch {
          localFallbackQueue.push(entry);
        }
      }
    }
  }

  // Mover itens de processing de volta para a fila principal (ap├│s backoff impl├¡cito do intervalo)
  try {
    let item = await redis.lPop(AUDIT_DLQ_PROCESSING);
    while (item) {
      await redis.rPush(AUDIT_DLQ_KEY, item);
      item = await redis.lPop(AUDIT_DLQ_PROCESSING);
    }
  } catch {
    // Silencioso
  }

  return { processados, falhas };
}

/**
 * Alertar administrador sobre falha definitiva na auditoria.
 * Loga em n├¡vel CRITICAL e registra na tabela de alertas.
 */
async function alertarFalhaAuditoria(entry: AuditEntry, error: Error): Promise<void> {
  console.error(
    `[audit-dlq] ALERTA: registro de auditoria perdido ap├│s ${MAX_RETRIES} tentativas!`,
    { acao: entry.acao, tabela: entry.tabela, registro_id: entry.registro_id, error: error.message },
  );

  // Tentar registrar o alerta no banco (em tabela separada, n├úo no audit_log)
  try {
    await getPool().query(
      `INSERT INTO alertas_sistema (tipo, severidade, mensagem, dados, criado_em)
       VALUES ('AUDITORIA_FALHA', 'critical', $1, $2, NOW())
       ON CONFLICT DO NOTHING`,
      [
        `Falha ao gravar auditoria ap├│s ${MAX_RETRIES} tentativas: ${entry.acao} em ${entry.tabela}`,
        JSON.stringify({ entry, error: error.message, first_failed_at: entry._first_failed_at }),
      ],
    );
  } catch {
    // Se at├® isso falhar, j├í est├í no console.error acima
  }
}

/**
 * Obter estat├¡sticas da fila.
 */
export async function obterEstatisticasDLQ(): Promise<{
  pendentes_redis: number;
  pendentes_local: number;
  mortos: number;
}> {
  const redis = getRedis();
  let pendentes_redis = 0;
  let mortos = 0;

  if (redis) {
    try {
      pendentes_redis = await redis.lLen(AUDIT_DLQ_KEY);
      mortos = await redis.lLen("audit:dead");
    } catch {
      // Redis offline
    }
  }

  return {
    pendentes_redis,
    pendentes_local: localFallbackQueue.length,
    mortos,
  };
}

// ÔöÇÔöÇ Iniciar processamento peri├│dico ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

let intervalo: ReturnType<typeof setInterval> | null = null;

export function iniciarProcessamentoDLQ(intervalMs = 30_000): void {
  if (intervalo) return;
  intervalo = setInterval(async () => {
    try {
      const stats = await processarFilaAuditoria();
      if (stats.processados > 0 || stats.falhas > 0) {
        console.info(`[audit-dlq] Processados: ${stats.processados}, Falhas: ${stats.falhas}`);
      }
    } catch (err) {
      console.error("[audit-dlq] Erro no processamento:", (err as Error).message);
    }
  }, intervalMs);
}

export function pararProcessamentoDLQ(): void {
  if (intervalo) {
    clearInterval(intervalo);
    intervalo = null;
  }
}

