        {/* Perfil resumido */}
        {!collapsed && servidor && (
          <div className="px-3 py-2">
            <p className="text-xs font-medium text-superadmin-sidebar-foreground truncate">{servidor.nome}</p>
            <p className="text-[10px] text-superadmin-sidebar-muted truncate">{servidor.email}</p>
