import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Underline from "@tiptap/extension-underline";
import TextAlign from "@tiptap/extension-text-align";
import Highlight from "@tiptap/extension-highlight";
import Placeholder from "@tiptap/extension-placeholder";
import { TextStyle } from "@tiptap/extension-text-style";
import Color from "@tiptap/extension-color";
import FontFamily from "@tiptap/extension-font-family";
import { Table as TableExt } from "@tiptap/extension-table";
import { TableRow } from "@tiptap/extension-table-row";
import { TableCell } from "@tiptap/extension-table-cell";
import { TableHeader } from "@tiptap/extension-table-header";
import ImageExt from "@tiptap/extension-image";
import { useEffect, useCallback, useRef } from "react";
import { ContratoToolbar } from "./ContratoToolbar";

/* ÔöÇÔöÇ Font Size via TextStyle mark ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
const FontSize = TextStyle.extend({
  addAttributes() {
    return {
      ...this.parent?.(),
      fontSize: {
        default: null,
        parseHTML: (el: HTMLElement) => el.style.fontSize || null,
        renderHTML: (attrs: Record<string, string>) => {
          if (!attrs.fontSize) return {};
          return { style: `font-size: ${attrs.fontSize}` };
        },
      },
    };
  },
});

interface ContratoEditorProps {
  contentHtml?: string;
  contentJson?: Record<string, unknown> | null;
  onChange?: (html: string, json: Record<string, unknown>) => void;
  editable?: boolean;
}

export function ContratoEditor({
  contentHtml,
  contentJson,
  onChange,
  editable = true,
}: ContratoEditorProps) {
  const onChangeRef = useRef(onChange);
  onChangeRef.current = onChange;

  const editor = useEditor({
    editable,
    extensions: [
      StarterKit.configure({
        heading: { levels: [1, 2, 3] },
      }),
      Underline,
      TextAlign.configure({ types: ["heading", "paragraph"] }),
      Highlight.configure({ multicolor: false }),
      Placeholder.configure({ placeholder: "Comece a escrever o conte├║do do contratoÔÇª" }),
      FontSize,
      Color,
      FontFamily,
      TableExt.configure({ resizable: true }),
      TableRow,
      TableCell,
      TableHeader,
      ImageExt.configure({ inline: true }),
    ],
    content: contentJson || contentHtml || "",
    onUpdate: ({ editor: ed }) => {
      onChangeRef.current?.(ed.getHTML(), ed.getJSON() as Record<string, unknown>);
    },
  });

  // Sync editable prop
  useEffect(() => {
    if (editor) editor.setEditable(editable);
  }, [editor, editable]);

  // Sync external content changes (e.g. loading from API)
  const setContentOnce = useCallback(
    (html: string | undefined, json: Record<string, unknown> | null | undefined) => {
      if (!editor) return;
      const curr = editor.getHTML();
      if (json && Object.keys(json).length > 0) {
        // avoid unnecessary re-rendering
        if (curr !== "<p></p>" && curr.length > 20) return;
        editor.commands.setContent(json);
      } else if (html && html !== curr) {
        editor.commands.setContent(html);
      }
    },
    [editor],
  );

  useEffect(() => {
    setContentOnce(contentHtml, contentJson);
  }, [contentHtml, contentJson, setContentOnce]);

  return (
    <div className="rounded-xl border bg-card overflow-hidden">
      {editable && <ContratoToolbar editor={editor} />}
      <EditorContent
        editor={editor}
        className="prose prose-sm dark:prose-invert max-w-none min-h-100 px-6 py-4 focus-within:outline-none
          [&_.ProseMirror]:min-h-95 [&_.ProseMirror]:outline-none
          [&_.ProseMirror_table]:border-collapse [&_.ProseMirror_td]:border [&_.ProseMirror_td]:px-3 [&_.ProseMirror_td]:py-1.5
          [&_.ProseMirror_th]:border [&_.ProseMirror_th]:px-3 [&_.ProseMirror_th]:py-1.5 [&_.ProseMirror_th]:bg-muted/50 [&_.ProseMirror_th]:font-semibold
          [&_.ProseMirror_p.is-editor-empty:first-child::before]:text-muted-foreground/50 [&_.ProseMirror_p.is-editor-empty:first-child::before]:content-[attr(data-placeholder)] [&_.ProseMirror_p.is-editor-empty:first-child::before]:float-left [&_.ProseMirror_p.is-editor-empty:first-child::before]:h-0 [&_.ProseMirror_p.is-editor-empty:first-child::before]:pointer-events-none"
      />
    </div>
  );
}

import { useCallback } from "react";
import { useSearchParams } from "react-router-dom";
import { Filter, X } from "lucide-react";

interface DashboardFiltrosProps {
  ufs: string[];
  carregandoUfs: boolean;
}

const PERIODOS = [
  { label: "30 dias", value: "30" },
  { label: "60 dias", value: "60" },
  { label: "90 dias", value: "90" },
  { label: "180 dias", value: "180" },
  { label: "1 ano", value: "365" },
];

const STATUS_CONTRATO = [
  { label: "Ativo", value: "ativo" },
  { label: "Rascunho", value: "rascunho" },
  { label: "Pend. Assinatura", value: "pendente_assinatura" },
  { label: "Suspenso", value: "suspenso" },
  { label: "Encerrado", value: "encerrado" },
  { label: "Cancelado", value: "cancelado" },
  { label: "Renova├º├úo", value: "renovacao" },
];

export function useDashboardFiltros() {
  const [searchParams, setSearchParams] = useSearchParams();

  const dias = searchParams.get("dias") || "365";
  const uf = searchParams.get("uf") || "";
  const status = searchParams.get("status") || "";

  const setFiltro = useCallback(
    (key: string, value: string) => {
      setSearchParams((prev) => {
        const next = new URLSearchParams(prev);
        if (value) {
          next.set(key, value);
        } else {
          next.delete(key);
        }
        return next;
      });
    },
    [setSearchParams],
  );

  const limparFiltros = useCallback(() => {
    setSearchParams({});
  }, [setSearchParams]);

  const temFiltros = uf !== "" || status !== "" || dias !== "365";

  return { dias, uf, status, setFiltro, limparFiltros, temFiltros };
}

export function DashboardFiltros({ ufs, carregandoUfs }: DashboardFiltrosProps) {
  const { dias, uf, status, setFiltro, limparFiltros, temFiltros } = useDashboardFiltros();

  return (
    <div className="flex flex-wrap items-center gap-3">
      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
        <Filter className="h-3.5 w-3.5" />
        <span>Filtros</span>
      </div>

      {/* Per├¡odo */}
      <select
        value={dias}
        onChange={(e) => setFiltro("dias", e.target.value === "365" ? "" : e.target.value)}
        className="rounded-md border bg-background px-2 py-1.5 text-xs focus:outline-none focus:ring-2 focus:ring-superadmin-accent"
      >
        {PERIODOS.map((p) => (
          <option key={p.value} value={p.value}>
            {p.label}
          </option>
        ))}
      </select>

      {/* UF */}
      <select
        value={uf}
        onChange={(e) => setFiltro("uf", e.target.value)}
        disabled={carregandoUfs}
        className="rounded-md border bg-background px-2 py-1.5 text-xs focus:outline-none focus:ring-2 focus:ring-superadmin-accent disabled:opacity-50"
      >
        <option value="">Todas as UFs</option>
        {ufs.map((u) => (
          <option key={u} value={u}>
            {u}
          </option>
        ))}
      </select>

      {/* Status */}
      <select
        value={status}
        onChange={(e) => setFiltro("status", e.target.value)}
        className="rounded-md border bg-background px-2 py-1.5 text-xs focus:outline-none focus:ring-2 focus:ring-superadmin-accent"
      >
        <option value="">Todos os status</option>
        {STATUS_CONTRATO.map((s) => (
          <option key={s.value} value={s.value}>
            {s.label}
          </option>
        ))}
      </select>

      {/* Limpar */}
      {temFiltros && (
        <button
          type="button"
          onClick={limparFiltros}
          className="flex items-center gap-1 rounded-md bg-muted px-2 py-1.5 text-xs text-muted-foreground hover:bg-muted/80 transition-colors"
        >
          <X className="h-3 w-3" />
          Limpar
        </button>
      )}
    </div>
  );
}

