const TIMEOUT_INATIVIDADE_MS = 30 * 60 * 1000; // 30 minutos
const EVENTOS_ATIVIDADE = ["mousedown", "keydown", "scroll", "touchstart"] as const;

// ÔöÇÔöÇÔöÇ Tipos do contexto ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export interface AuthContextoValor {
  /** Usu├írio do Firebase Auth */
  usuario: User | null;
  /** Dados completos do servidor (tabela `servidores`) */
  servidor: Servidor | null;
  /** Perfil textual do servidor logado */
  perfil: PerfilNome | null;
  /** Carregando estado inicial de auth */
  carregando: boolean;
  /** Login com e-mail e senha */
  login: (email: string, senha: string) => Promise<{ erro: string | null }>;
  /** Logout */
  logout: () => Promise<void>;
  /** Recupera├º├úo de senha */
  recuperarSenha: (email: string) => Promise<{ erro: string | null }>;
  /** Redefinir senha (ap├│s link do e-mail) */
  redefinirSenha: (novaSenha: string, oobCode: string) => Promise<{ erro: string | null }>;
  /** Verifica se o perfil do usu├írio est├í na lista permitida */
  temPermissao: (...perfis: PerfilNome[]) => boolean;
  /** Indica se o servidor logado ├® SuperAdmin da plataforma */
  isSuperAdmin: boolean;
}

// ÔöÇÔöÇÔöÇ Contexto ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export const AuthContexto = createContext<AuthContextoValor | undefined>(undefined);

// ÔöÇÔöÇÔöÇ Provider ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [usuario, setUsuario] = useState<User | null>(null);
  const [servidor, setServidor] = useState<Servidor | null>(null);
  const [carregando, setCarregando] = useState(true);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // ÔöÇÔöÇ Buscar dados do servidor via API ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const carregarServidor = useCallback(async () => {
    try {
      const res = await api.get<{ data: Servidor }>("/api/servidores/me");
      setServidor(res.data ?? null);
    } catch (e) {
      console.error("Erro ao carregar servidor:", e);
      setServidor(null);
    }
  }, []);

  // ÔöÇÔöÇ Logout ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const logout = useCallback(async () => {
    await signOut(auth);
    setUsuario(null);
    setServidor(null);
  }, []);

  // ÔöÇÔöÇ Timeout por inatividade ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const resetarTimeout = useCallback(() => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    timeoutRef.current = setTimeout(() => {
      logout();
    }, TIMEOUT_INATIVIDADE_MS);
  }, [logout]);

  useEffect(() => {
    if (!usuario) return;
    resetarTimeout();
    const handler = () => resetarTimeout();
    for (const ev of EVENTOS_ATIVIDADE) {
      window.addEventListener(ev, handler, { passive: true });
    }
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      for (const ev of EVENTOS_ATIVIDADE) {
        window.removeEventListener(ev, handler);
      }
    };
  }, [usuario, resetarTimeout]);

  // ÔöÇÔöÇ Inicializar sess├úo com Firebase Auth ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      setUsuario(firebaseUser);
      if (firebaseUser) {
        carregarServidor();
      } else {
        setServidor(null);
      }
      setCarregando(false);
    });
    return () => unsubscribe();
  }, [carregarServidor]);

  // ÔöÇÔöÇ Login ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const login = useCallback(
    async (email: string, senha: string): Promise<{ erro: string | null }> => {
      try {
        await signInWithEmailAndPassword(auth, email, senha);
        return { erro: null };
      } catch (error: unknown) {
        const code = (error as { code?: string }).code ?? "";
        const mensagens: Record<string, string> = {
          "auth/invalid-credential": "E-mail ou senha inv├ílidos.",
          "auth/user-not-found": "Usu├írio n├úo encontrado.",
          "auth/wrong-password": "Senha incorreta.",
          "auth/too-many-requests": "Muitas tentativas. Tente novamente mais tarde.",
          "auth/user-disabled": "Conta desativada. Contate o administrador.",
        };
        return { erro: mensagens[code] || "Erro ao fazer login." };
      }
    },
    [],
  );

  // ÔöÇÔöÇ Recuperar senha ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const recuperarSenha = useCallback(
    async (email: string): Promise<{ erro: string | null }> => {
      try {
        await sendPasswordResetEmail(auth, email, {
          url: `${window.location.origin}/redefinir-senha`,
        });
        return { erro: null };
      } catch {
        return { erro: "Erro ao enviar e-mail de recupera├º├úo." };
      }
    },
    [],
  );

  // ÔöÇÔöÇ Redefinir senha ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const redefinirSenha = useCallback(
    async (novaSenha: string, oobCode: string): Promise<{ erro: string | null }> => {
      try {
        await confirmPasswordReset(auth, oobCode, novaSenha);
        return { erro: null };
      } catch {
        return { erro: "Erro ao redefinir senha. O link pode ter expirado." };
      }
    },
    [],
  );

  // ÔöÇÔöÇ Helpers derivados ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const perfil = useMemo<PerfilNome | null>(() => {
    if (!servidor?.perfil) return null;
    return (servidor.perfil as unknown as { nome: PerfilNome }).nome;
  }, [servidor]);

  const isSuperAdmin = useMemo(() => !!servidor?.is_superadmin, [servidor]);

  const temPermissao = useCallback(
    (...perfis: PerfilNome[]) => {
      if (isSuperAdmin) return true;
      if (!perfil) return false;
      return perfis.includes(perfil);
    },
    [perfil, isSuperAdmin],
  );

  // ÔöÇÔöÇ Valor do contexto ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const valor = useMemo<AuthContextoValor>(
    () => ({
      usuario,
      servidor,
      perfil,
      carregando,
      login,
      logout,
      recuperarSenha,
      redefinirSenha,
      temPermissao,
      isSuperAdmin,
    }),
    [usuario, servidor, perfil, carregando, login, logout, recuperarSenha, redefinirSenha, temPermissao, isSuperAdmin],
  );

  return (
    <AuthContexto.Provider value={valor}>
      {children}
    </AuthContexto.Provider>
  );
}

import { createContext, useContext, useEffect, useState, type ReactNode } from "react";

type Theme = "light" | "dark" | "system";

interface ThemeContextType {
  theme: Theme;
  resolved: "light" | "dark";
  setTheme: (t: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType | null>(null);

const STORAGE_KEY = "licitanest-theme";

function getSystemTheme(): "light" | "dark" {
  return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
}

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeRaw] = useState<Theme>(() => {
    const stored = localStorage.getItem(STORAGE_KEY) as Theme | null;
    return stored ?? "light";
  });

  const resolved = theme === "system" ? getSystemTheme() : theme;

  useEffect(() => {
    const root = document.documentElement;
    root.classList.remove("light", "dark");
    root.classList.add(resolved);
    localStorage.setItem(STORAGE_KEY, theme);
  }, [theme, resolved]);

  // Listen for OS theme changes when "system" is selected
  useEffect(() => {
    if (theme !== "system") return;
    const mq = window.matchMedia("(prefers-color-scheme: dark)");
    const handler = () => setThemeRaw((t) => (t === "system" ? "system" : t)); // Re-trigger resolved
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, [theme]);

  const setTheme = (t: Theme) => setThemeRaw(t);

  return (
    <ThemeContext.Provider value={{ theme, resolved, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error("useTheme deve estar dentro do ThemeProvider");
  return ctx;
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
// Hooks de Cota├º├úo Eletr├┤nica ÔÇö Fase 9
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import { useCallback, useRef, useState } from "react";
import type {
  Cotacao,
  CriarCotacaoDTO,
  StatusCotacao,
  RespostaCotacao,
  LancamentoManual,
  DadosPortalFornecedor,
  MeioRecebimento,
} from "@/tipos";
import {
  listarCotacoes,
  obterCotacao,
  criarCotacao,
  atualizarCotacao,
  alterarStatusCotacao,
  excluirCotacao,
  enviarCotacao,
  listarRespostasCotacao,
  listarLancamentosManuais,
  criarLancamentoManual,
  transferirRespostaParaCesta,
  transferirLancamentoParaCesta,
  buscarPortalPorToken,
  salvarRespostasPortal,
  type FiltrosCotacoes,
} from "@/servicos/cotacoes";

// ÔöÇÔöÇ Hook: lista paginada de cota├º├Áes ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export function useCotacoesPaginadas() {
  const [cotacoes, setCotacoes] = useState<Cotacao[]>([]);
  const [total, setTotal] = useState(0);
  const [carregando, setCarregando] = useState(false);
  const [erro, setErro] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const carregar = useCallback(async (filtros?: FiltrosCotacoes, pagina = 1) => {
    abortRef.current?.abort();
    abortRef.current = new AbortController();

    setCarregando(true);
    setErro(null);
    try {
      const result = await listarCotacoes(filtros, pagina);
      setCotacoes(result.data);
      setTotal(result.total);
    } catch (e: any) {
      if (e instanceof DOMException && e.name === 'AbortError') return;
      setErro(e.message);
    } finally {
      setCarregando(false);
    }
  }, []);

  return { cotacoes, total, carregando, erro, carregar };
}

// ÔöÇÔöÇ Hook: detalhe de cota├º├úo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export function useCotacaoDetalhe() {
  const [cotacao, setCotacao] = useState<Cotacao | null>(null);
  const [respostas, setRespostas] = useState<RespostaCotacao[]>([]);
  const [lancamentos, setLancamentos] = useState<LancamentoManual[]>([]);
  const [carregando, setCarregando] = useState(false);
  const [erro, setErro] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const carregar = useCallback(async (id: string) => {
    abortRef.current?.abort();
    abortRef.current = new AbortController();

    setCarregando(true);
    setErro(null);
    try {
      const [cot, resps, lancs] = await Promise.all([
        obterCotacao(id),
        listarRespostasCotacao(id),
        listarLancamentosManuais(id),
      ]);
      setCotacao(cot);
      setRespostas(resps);
      setLancamentos(lancs);
    } catch (e: any) {
      if (e instanceof DOMException && e.name === 'AbortError') return;
      setErro(e.message);
    } finally {
      setCarregando(false);
    }
  }, []);

  const criar = useCallback(async (dto: CriarCotacaoDTO) => {
    setCarregando(true);
    setErro(null);
    try {
      const c = await criarCotacao(dto);
      setCotacao(c);
      return c;
    } catch (e: any) {
      setErro(e.message);
      return null;
    } finally {
      setCarregando(false);
    }
  }, []);

  const atualizar = useCallback(async (id: string, campos: Partial<Pick<Cotacao, "titulo" | "descricao" | "data_encerramento">>) => {
    try {
      const c = await atualizarCotacao(id, campos);
      setCotacao(c);
      return c;
    } catch (e: any) {
      setErro(e.message);
      return null;
    }
  }, []);

  const alterarStatus = useCallback(async (id: string, status: StatusCotacao) => {
    try {
      const c = await alterarStatusCotacao(id, status);
      setCotacao(prev => prev ? { ...prev, status: c.status } : prev);
      return c;
    } catch (e: any) {
      setErro(e.message);
      return null;
    }
  }, []);

  const enviar = useCallback(async (id: string) => {
    setCarregando(true);
    try {
      const c = await enviarCotacao(id);
      setCotacao(c);
      return c;
    } catch (e: any) {
      setErro(e.message);
      return null;
    } finally {
      setCarregando(false);
    }
  }, []);

  const excluir = useCallback(async (id: string) => {
    try {
      await excluirCotacao(id);
      setCotacao(null);
    } catch (e: any) {
      setErro(e.message);
    }
  }, []);

  const transferirResposta = useCallback(async (respostaId: string, servidorId: string) => {
    try {
      await transferirRespostaParaCesta(respostaId, servidorId);
      // Recarregar respostas
      if (cotacao) {
        const resps = await listarRespostasCotacao(cotacao.id);
        setRespostas(resps);
      }
    } catch (e: any) {
      setErro(e.message);
    }
  }, [cotacao]);

  const lancarManual = useCallback(async (
    cotacaoId: string,
    lancamento: {
      item_cesta_id: string;
      razao_social: string;
      cpf_cnpj?: string;
      email?: string;
      telefone?: string;
      marca?: string;
      valor_unitario: number;
      valor_total?: number;
      observacoes?: string;
      registro_anvisa?: string;
      meio_recebimento: MeioRecebimento;
      lancado_por: string;
    },
  ) => {
    try {
      const lanc = await criarLancamentoManual(cotacaoId, lancamento);
      setLancamentos(prev => [lanc, ...prev]);
      return lanc;
    } catch (e: any) {
      setErro(e.message);
      return null;
    }
  }, []);

  const transferirLancamento = useCallback(async (lancamentoId: string, servidorId: string) => {
    try {
      await transferirLancamentoParaCesta(lancamentoId, servidorId);
      setLancamentos(prev => prev.map(l => l.id === lancamentoId ? { ...l, transferido_cesta: true, transferido_em: new Date().toISOString() } : l));
    } catch (e: any) {
      setErro(e.message);
    }
  }, []);

  return {
    cotacao,
    respostas,
    lancamentos,
    carregando,
    erro,
    carregar,
    criar,
    atualizar,
    alterarStatus,
    enviar,
    excluir,
    transferirResposta,
    lancarManual,
    transferirLancamento,
  };
}

// ÔöÇÔöÇ Hook: portal do fornecedor (p├║blico) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export function usePortalFornecedor() {
  const [dados, setDados] = useState<DadosPortalFornecedor | null>(null);
  const [carregando, setCarregando] = useState(false);
  const [salvando, setSalvando] = useState(false);
  const [erro, setErro] = useState<string | null>(null);
  const [sucesso, setSucesso] = useState(false);
  const abortRef = useRef<AbortController | null>(null);

  const carregarPorToken = useCallback(async (token: string) => {
    abortRef.current?.abort();
    abortRef.current = new AbortController();

    setCarregando(true);
    setErro(null);
    try {
      const d = await buscarPortalPorToken(token);
      setDados(d);
    } catch (e: any) {
      if (e instanceof DOMException && e.name === 'AbortError') return;
      setErro(e.message);
    } finally {
      setCarregando(false);
    }
  }, []);

  const salvarRespostas = useCallback(async (
    fornecedorId: string,
    respostas: {
      cotacao_item_id: string;
      marca?: string;
      valor_unitario: number;
      valor_total?: number;
      observacoes?: string;
      registro_anvisa?: string;
    }[],
    dadosFornecedor?: {
      endereco_completo?: string;
      cep?: string;
      cidade?: string;
      uf?: string;
      prazo_validade_dias?: number;
      nome_responsavel?: string;
      cpf_responsavel?: string;
    },
    csrfToken?: string,
  ) => {
    setSalvando(true);
    setErro(null);
    setSucesso(false);
    try {
      await salvarRespostasPortal(fornecedorId, respostas, dadosFornecedor, csrfToken);
      setSucesso(true);
    } catch (e: any) {
      setErro(e.message);
    } finally {
      setSalvando(false);
    }
  }, []);

  return { dados, carregando, salvando, erro, sucesso, carregarPorToken, salvarRespostas };
}

