// Sentry ÔÇö Observabilidade e Crash Reporting
// Configure VITE_SENTRY_DSN no .env para ativar
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import * as Sentry from "@sentry/react";

const SENTRY_DSN = import.meta.env.VITE_SENTRY_DSN ?? "";
const ENVIRONMENT = import.meta.env.MODE ?? "development";

export function initSentry() {
  if (!SENTRY_DSN) {
    console.info("[Sentry] DSN n├úo configurado ÔÇö monitoramento desativado");
    return;
  }

  Sentry.init({
    dsn: SENTRY_DSN,
    environment: ENVIRONMENT,
    integrations: [
      Sentry.browserTracingIntegration(),
      Sentry.replayIntegration({
        maskAllText: true,
        blockAllMedia: true,
      }),
    ],
    // Taxa de amostragem de performance (10% em prod, 100% em dev)
    tracesSampleRate: ENVIRONMENT === "production" ? 0.1 : 1.0,
    // Replay de sess├úo: 10% normais, 100% em erros
    replaysSessionSampleRate: 0.1,
    replaysOnErrorSampleRate: 1.0,
    // N├úo enviar dados sens├¡veis
    beforeSend(event) {
      // Remover dados potencialmente sens├¡veis
      if (event.request?.cookies) {
        delete event.request.cookies;
      }
      return event;
    },
    // Ignorar erros de rede comuns
    ignoreErrors: [
      "Network Error",
      "Failed to fetch",
      "Load failed",
      "AbortError",
      "ResizeObserver loop",
    ],
  });
}

export function setSentryUser(user: { id: string; email?: string; municipio?: string }) {
  Sentry.setUser({
    id: user.id,
    email: user.email,
    // N├úo enviar dados pessoais extras ÔÇö apenas contexto de tenant
  });
  if (user.municipio) {
    Sentry.setTag("municipio", user.municipio);
  }
}

export function clearSentryUser() {
  Sentry.setUser(null);
}

export function captureError(error: Error, context?: Record<string, unknown>) {
  Sentry.captureException(error, {
    extra: context,
  });
}

export { Sentry };

import { useState, useEffect, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/componentes/ui/card";
