import {
  Bell, BellOff, BellRing, Plus, Trash2, Check, TrendingUp, TrendingDown,
  AlertTriangle, Settings2,
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import {
  listarConfiguracoes, criarConfiguracao, excluirConfiguracao,
  listarAlertas, resolverAlerta, silenciarAlerta,
} from "@/servicos/alertasPreco";
import { api } from "@/lib/api";
import { useConfirm } from "@/componentes/ui/confirm-dialog";
import type { ConfigAlerta, AlertaPreco, TipoAlerta } from "@/tipos";
import { toast } from "sonner";

interface ProdutoSimples {
  id: string;
  descricao: string;
  unidade: string;
  codigo_catmat?: string;
}

export function AlertasPrecoPage() {
  const { servidor } = useAuth();
  const confirm = useConfirm();
  const [tab, setTab] = useState<"alertas" | "config">("alertas");
  const [configs, setConfigs] = useState<ConfigAlerta[]>([]);
  const [alertas, setAlertas] = useState<AlertaPreco[]>([]);
  const [carregando, setCarregando] = useState(true);

  // Form novo alerta
  const [showForm, setShowForm] = useState(false);
  const [buscaProduto, setBuscaProduto] = useState("");
  const [produtosSugestao, setProdutosSugestao] = useState<ProdutoSimples[]>([]);
  const [produtoSelecionado, setProdutoSelecionado] = useState<ProdutoSimples | null>(null);
  const [percentual, setPercentual] = useState("15");
  const [tipo, setTipo] = useState<TipoAlerta>("variacao_preco");
  const [notificarEmail, setNotificarEmail] = useState(true);
  const [salvando, setSalvando] = useState(false);

  const carregar = useCallback(async () => {
    if (!servidor) return;
    setCarregando(true);
    try {
      const [c, a] = await Promise.all([
        listarConfiguracoes(servidor.id),
        listarAlertas(servidor.id),
      ]);
      setConfigs(c);
      setAlertas(a);
    } catch {
      toast.error("Erro ao carregar alertas.");
    } finally {
      setCarregando(false);
    }
  }, [servidor]);

  useEffect(() => { carregar(); }, [carregar]);

  /* Buscar produto para o formul├írio */
  const buscarProdutos = async () => {
    if (buscaProduto.trim().length < 2) return;
    const data = await api.get<ProdutoSimples[]>(
      `/api/produtos-catalogo?descricao=${encodeURIComponent(buscaProduto.trim())}&limit=8`
    );
    setProdutosSugestao(data ?? []);
  };

  /* Criar nova configura├º├úo */
  const handleCriar = async () => {
    if (!servidor || !produtoSelecionado) return;
    const pct = Number(percentual);
    if (isNaN(pct) || pct <= 0 || pct > 100) {
      toast.error("Percentual inv├ílido (1 a 100).");
      return;
    }
    setSalvando(true);
    try {
      await criarConfiguracao({
        servidor_id: servidor.id,
        produto_id: produtoSelecionado.id,
        cesta_id: null,
        tipo,
        percentual_gatilho: pct,
        notificar_email: notificarEmail,
        ativo: true,
      });
      toast.success("Alerta configurado com sucesso!");
      setShowForm(false);
      setProdutoSelecionado(null);
      setBuscaProduto("");
      setPercentual("15");
      carregar();
    } catch {
      toast.error("Erro ao criar configura├º├úo.");
    } finally {
      setSalvando(false);
    }
  };

  /* Excluir config */
  const handleExcluir = async (id: string) => {
    const ok = await confirm({
      title: "Excluir configura├º├úo?",
      description: "Esta a├º├úo n├úo pode ser desfeita.",
      confirmLabel: "Excluir",
      variant: "danger",
    });
    if (!ok) return;
    try {
      await excluirConfiguracao(id);
      toast.success("Configura├º├úo exclu├¡da.");
      carregar();
    } catch {
      toast.error("Erro ao excluir.");
    }
  };

  /* A├º├Áes em alertas */
  const handleResolver = async (id: string) => {
    await resolverAlerta(id);
    toast.success("Alerta resolvido.");
    carregar();
  };
  const handleSilenciar = async (id: string) => {
    await silenciarAlerta(id);
    toast.info("Alerta silenciado.");
    carregar();
  };

  const alertasAtivos = alertas.filter((a) => a.status === "ativo");

  return (
    <PageTransition>
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <BellRing className="h-6 w-6 text-primary" />
              Alertas de Varia├º├úo de Pre├ºo
            </h1>
            <p className="text-muted-foreground mt-1">
              Configure alertas para ser notificado quando pre├ºos variam acima de um percentual.
            </p>
          </div>
          {alertasAtivos.length > 0 && (
            <span className="flex items-center gap-1 rounded-full bg-red-100 text-red-700 px-3 py-1 text-sm font-medium dark:bg-red-900/30 dark:text-red-400">
              <AlertTriangle className="h-4 w-4" />
              {alertasAtivos.length} ativo{alertasAtivos.length !== 1 ? "s" : ""}
            </span>
          )}
        </div>

        {/* Tabs */}
        <div className="flex gap-1 border-b">
          <button
            onClick={() => setTab("alertas")}
            className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${tab === "alertas" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
          >
            <Bell className="h-4 w-4 inline mr-1" />
            Alertas ({alertas.length})
          </button>
          <button
            onClick={() => setTab("config")}
            className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${tab === "config" ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"}`}
          >
            <Settings2 className="h-4 w-4 inline mr-1" />
            Configura├º├Áes ({configs.length})
          </button>
        </div>

        {carregando && <SkeletonTable rows={5} cols={5} />}

        {/* ÔöÇÔöÇ Tab Alertas ÔöÇÔöÇ */}
        {!carregando && tab === "alertas" && (
          <>
            {alertas.length === 0 ? (
              <EmptyState
                icon={Bell}
                title="Nenhum alerta disparado"
                description="Quando um pre├ºo variar acima do percentual configurado, o alerta aparecer├í aqui."
              />
            ) : (
              <div className="space-y-3">
                {alertas.map((a) => (
                  <Card key={a.id} className={a.status === "ativo" ? "border-red-300 dark:border-red-800" : "opacity-70"}>
                    <CardContent className="flex items-center justify-between py-4">
                      <div className="flex items-center gap-4">
                        <div className={`p-2 rounded-lg ${a.variacao_percentual > 0 ? "bg-red-100 text-red-600 dark:bg-red-900/30" : "bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30"}`}>
                          {a.variacao_percentual > 0 ? <TrendingUp className="h-5 w-5" /> : <TrendingDown className="h-5 w-5" />}
                        </div>
                        <div>
                          <p className="font-medium text-sm">{a.produto?.descricao ?? "Produto"}</p>
                          <p className="text-xs text-muted-foreground">
                            R$ {a.valor_anterior.toFixed(2)} ÔåÆ R$ {a.valor_atual.toFixed(2)}
                            {" ┬À "}
                            <span className={a.variacao_percentual > 0 ? "text-red-500 font-medium" : "text-emerald-500 font-medium"}>
                              {a.variacao_percentual > 0 ? "+" : ""}{a.variacao_percentual.toFixed(1)}%
                            </span>
                            {" ┬À "}
                            Fonte: {a.fonte_nome}
                          </p>
                          <p className="text-xs text-muted-foreground mt-0.5">
                            Status: <span className="capitalize">{a.status}</span>
                            {" ┬À "}
                            {new Date(a.criado_em).toLocaleDateString("pt-BR")}
                          </p>
                        </div>
                      </div>

                      {a.status === "ativo" && (
                        <div className="flex gap-2">
                          <Button size="sm" variant="outline" onClick={() => handleSilenciar(a.id)}>
                            <BellOff className="h-4 w-4 mr-1" /> Silenciar
                          </Button>
                          <Button size="sm" onClick={() => handleResolver(a.id)}>
                            <Check className="h-4 w-4 mr-1" /> Resolver
                          </Button>
                        </div>
                      )}
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </>
        )}

        {/* ÔöÇÔöÇ Tab Configura├º├Áes ÔöÇÔöÇ */}
        {!carregando && tab === "config" && (
          <>
            <div className="flex justify-end">
              <Button onClick={() => setShowForm((v) => !v)}>
                <Plus className="h-4 w-4 mr-2" />
                Novo Alerta
              </Button>
            </div>

            {showForm && (
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Nova Configura├º├úo de Alerta</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  {/* Busca produto */}
                  <div>
                    <label className="text-sm font-medium mb-1 block">Produto</label>
                    {produtoSelecionado ? (
                      <div className="flex items-center gap-2">
                        <span className="text-sm">{produtoSelecionado.descricao}</span>
                        <Button size="sm" variant="ghost" onClick={() => setProdutoSelecionado(null)}>Ô£ò</Button>
                      </div>
                    ) : (
                      <div className="flex gap-2">
                        <Input
                          placeholder="Buscar produto..."
                          value={buscaProduto}
                          onChange={(e) => setBuscaProduto(e.target.value)}
                          onKeyDown={(e) => e.key === "Enter" && buscarProdutos()}
                        />
                        <Button variant="outline" onClick={buscarProdutos}>Buscar</Button>
                      </div>
                    )}
                    {produtosSugestao.length > 0 && !produtoSelecionado && (
                      <div className="mt-2 border rounded divide-y max-h-36 overflow-y-auto">
                        {produtosSugestao.map((p) => (
                          <button
                            key={p.id}
                            onClick={() => { setProdutoSelecionado(p); setProdutosSugestao([]); }}
                            className="w-full text-left px-3 py-1.5 text-sm hover:bg-accent"
                          >
                            {p.descricao} ({p.unidade})
                          </button>
                        ))}
                      </div>
                    )}
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                    <div>
                      <label className="text-sm font-medium mb-1 block">Tipo</label>
                      <select
                        value={tipo}
                        onChange={(e) => setTipo(e.target.value as TipoAlerta)}
                        className="w-full rounded-md border bg-transparent px-3 py-2 text-sm"
                      >
                        <option value="variacao_preco">Varia├º├úo de Pre├ºo</option>
                        <option value="novo_preco">Novo Pre├ºo Registrado</option>
                        <option value="preco_expirado">Pre├ºo Expirado</option>
                      </select>
                    </div>
                    <div>
                      <label className="text-sm font-medium mb-1 block">Percentual Gatilho (%)</label>
                      <Input
                        type="number"
                        min={1}
                        max={100}
                        value={percentual}
                        onChange={(e) => setPercentual(e.target.value)}
                      />
                    </div>
                    <div className="flex items-end gap-2">
                      <label className="flex items-center gap-2 text-sm">
                        <input
                          type="checkbox"
                          checked={notificarEmail}
                          onChange={(e) => setNotificarEmail(e.target.checked)}
                          className="rounded"
                        />
                        Notificar por e-mail
                      </label>
                    </div>
                  </div>

                  <div className="flex justify-end gap-2">
                    <Button variant="outline" onClick={() => setShowForm(false)}>Cancelar</Button>
                    <Button onClick={handleCriar} disabled={salvando || !produtoSelecionado}>
                      {salvando ? "Salvando..." : "Salvar Alerta"}
                    </Button>
                  </div>
                </CardContent>
              </Card>
            )}

            {configs.length === 0 && !showForm ? (
              <EmptyState
                icon={Settings2}
                title="Nenhuma configura├º├úo"
                description="Crie uma configura├º├úo de alerta para monitorar varia├º├Áes de pre├ºo automaticamente."
                actionLabel="Novo Alerta"
                onAction={() => setShowForm(true)}
              />
            ) : (
              <div className="space-y-2">
                {configs.map((c) => (
                  <Card key={c.id}>
                    <CardContent className="flex items-center justify-between py-3">
                      <div>
                        <p className="font-medium text-sm">{c.produto?.descricao ?? (c.cesta as any)?.nome ?? "Geral"}</p>
                        <p className="text-xs text-muted-foreground">
                          Tipo: <span className="capitalize">{c.tipo.replace("_", " ")}</span>
                          {" ┬À "}Gatilho: ÔëÑ {c.percentual_gatilho}%
                          {" ┬À "}E-mail: {c.notificar_email ? "Sim" : "N├úo"}
                          {" ┬À "}{c.ativo ? "Ô£à Ativo" : "ÔÅ© Pausado"}
                        </p>
                      </div>
                      <Button size="sm" variant="ghost" onClick={() => handleExcluir(c.id)}>
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </>
        )}
      </div>
    </PageTransition>
  );
}

import { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { Card, CardContent } from "@/componentes/ui/card";
import { SkeletonTable } from "@/componentes/ui/skeleton";
import { EmptyState } from "@/componentes/ui/empty-state";
import { Button } from "@/componentes/ui/button";
import { Input } from "@/componentes/ui/input";
import { Badge } from "@/componentes/ui/badge";
import {
  FileSignature,
  Search,
  Eye,
  Clock,
  CheckCircle,
  XCircle,
  AlertTriangle,
  Pause,
  Bell,
  BellDot,
  ChevronRight,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { toast } from "sonner";
import {
  listarContratosPortal,
  listarNotificacoesPortal,
  marcarNotificacaoLida,
} from "@/servicos/contratos";
import type { Contrato, StatusContrato, ContratoNotificacao } from "@/tipos";

// ÔöÇÔöÇ Labels e variantes ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const STATUS_LABEL: Record<StatusContrato, string> = {
  rascunho: "Rascunho",
  pendente_assinatura: "Pendente Assinatura",
  ativo: "Ativo",
  suspenso: "Suspenso",
  encerrado: "Encerrado",
  cancelado: "Cancelado",
  renovacao: "Em Renova├º├úo",
};

const STATUS_VARIANT: Record<StatusContrato, string> = {
  rascunho: "secondary",
  pendente_assinatura: "warning",
  ativo: "success",
  suspenso: "warning",
  encerrado: "secondary",
  cancelado: "destructive",
  renovacao: "default",
};

const STATUS_ICON: Record<StatusContrato, React.ReactNode> = {
  rascunho: <Clock className="h-3 w-3" />,
  pendente_assinatura: <AlertTriangle className="h-3 w-3" />,
  ativo: <CheckCircle className="h-3 w-3" />,
  suspenso: <Pause className="h-3 w-3" />,
  encerrado: <XCircle className="h-3 w-3" />,
  cancelado: <XCircle className="h-3 w-3" />,
  renovacao: <Clock className="h-3 w-3" />,
};

const ASSINATURA_LABEL: Record<string, string> = {
  pendente: "Pendente",
  assinado: "Assinado",
  recusado: "Recusado",
  expirado: "Expirado",
};

const ASSINATURA_VARIANT: Record<string, string> = {
  pendente: "warning",
  assinado: "success",
  recusado: "destructive",
  expirado: "secondary",
};

function formatarMoeda(centavos: number): string {
  return new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(centavos / 100);
}

function calcularDiasRestantes(dataFim: string): number {
  return Math.ceil((new Date(dataFim).getTime() - Date.now()) / 86400000);
}

export function ContratosPortalPage() {
  const navigate = useNavigate();

  const [contratos, setContratos] = useState<Contrato[]>([]);
  const [notificacoes, setNotificacoes] = useState<ContratoNotificacao[]>([]);
  const [carregando, setCarregando] = useState(true);
  const [busca, setBusca] = useState("");
  const [statusFiltro, setStatusFiltro] = useState<string>("todos");

  const naoLidas = notificacoes.filter((n) => !n.lido);
  const pendentes = contratos.filter((c) => c.status === "pendente_assinatura");

  const carregar = useCallback(async () => {
    setCarregando(true);
    try {
      const [contRes, notRes] = await Promise.all([
        listarContratosPortal(),
        listarNotificacoesPortal(),
      ]);
      setContratos(contRes.data);
      setNotificacoes(notRes.data);
    } catch {
      toast.error("Erro ao carregar contratos");
    } finally {
      setCarregando(false);
    }
  }, []);

  useEffect(() => { carregar(); }, [carregar]);

  // Toast on load if pending contracts
  useEffect(() => {
    if (pendentes.length > 0) {
      toast.info(`Voc├¬ tem ${pendentes.length} contrato(s) aguardando assinatura`, {
        duration: 6000,
        action: {
          label: "Ver pendentes",
          onClick: () => setStatusFiltro("pendente_assinatura"),
        },
      });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pendentes.length]);

  const marcarLida = async (id: string) => {
    try {
      await marcarNotificacaoLida(id);
      setNotificacoes((prev) =>
        prev.map((n) => (n.id === id ? { ...n, lido: true, lido_em: new Date().toISOString() } : n)),
      );
    } catch {
      toast.error("Erro ao marcar notifica├º├úo como lida");
    }
  };

  // Filtering
  const filtrados = contratos.filter((c) => {
    if (statusFiltro !== "todos" && c.status !== statusFiltro) return false;
    if (busca) {
      const q = busca.toLowerCase();
      return (
        c.numero_contrato?.toLowerCase().includes(q) ||
        c.objeto?.toLowerCase().includes(q)
      );
    }
    return true;
  });

  // KPIs
  const kpi = {
    total: contratos.length,
    pendentes: pendentes.length,
    ativos: contratos.filter((c) => c.status === "ativo").length,
    vencendo30d: contratos.filter(
      (c) => c.status === "ativo" && c.data_fim && calcularDiasRestantes(c.data_fim) <= 30 && calcularDiasRestantes(c.data_fim) > 0,
    ).length,
  };

  return (
    <div className="space-y-6">
      {/* ÔöÇÔöÇ Header ÔöÇÔöÇ */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Contratos</h2>
          <p className="text-muted-foreground">
            Gerencie os contratos recebidos da plataforma
          </p>
        </div>
      </div>

      {/* ÔöÇÔöÇ Banner Pendentes ÔöÇÔöÇ */}
      <AnimatePresence>
        {pendentes.length > 0 && statusFiltro !== "pendente_assinatura" && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
          >
            <Card className="border-amber-500/50 bg-amber-50 dark:bg-amber-950/20">
              <CardContent className="flex items-center justify-between p-4">
                <div className="flex items-center gap-3">
                  <AlertTriangle className="h-5 w-5 text-amber-600" />
                  <span className="font-medium text-amber-800 dark:text-amber-200">
                    Voc├¬ tem {pendentes.length} contrato(s) aguardando assinatura
                  </span>
                </div>
                <Button
                  size="sm"
                  variant="outline"
                  className="border-amber-500 text-amber-700 hover:bg-amber-100"
                  onClick={() => setStatusFiltro("pendente_assinatura")}
                >
                  Ver pendentes
                </Button>
              </CardContent>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>

      {/* ÔöÇÔöÇ KPIs ÔöÇÔöÇ */}
      <div className="grid grid-cols-2 gap-4 lg:grid-cols-4">
        {[
          { label: "Total", value: kpi.total, icon: FileSignature, color: "text-blue-600" },
          { label: "Pendentes", value: kpi.pendentes, icon: AlertTriangle, color: "text-amber-600" },
          { label: "Ativos", value: kpi.ativos, icon: CheckCircle, color: "text-emerald-600" },
          { label: "Vencendo 30d", value: kpi.vencendo30d, icon: Clock, color: "text-red-600" },
        ].map((k) => (
          <Card key={k.label}>
            <CardContent className="flex items-center gap-3 p-4">
              <k.icon className={`h-8 w-8 ${k.color}`} />
              <div>
                <p className="text-2xl font-bold">{k.value}</p>
                <p className="text-xs text-muted-foreground">{k.label}</p>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* ÔöÇÔöÇ Notifica├º├Áes n├úo-lidas ÔöÇÔöÇ */}
      {naoLidas.length > 0 && (
        <Card>
          <CardContent className="p-4">
            <div className="mb-3 flex items-center gap-2">
              <BellDot className="h-4 w-4 text-primary" />
              <span className="text-sm font-semibold">
                Notifica├º├Áes ({naoLidas.length})
              </span>
            </div>
            <div className="space-y-2">
              {naoLidas.slice(0, 5).map((n) => (
                <div
                  key={n.id}
                  className="flex items-center justify-between rounded-lg border bg-muted/30 p-3"
                >
                  <div className="flex items-center gap-2">
                    <Bell className="h-4 w-4 text-amber-500" />
                    <div>
                      <p className="text-sm font-medium">{n.titulo}</p>
                      <p className="text-xs text-muted-foreground">{n.mensagem}</p>
                    </div>
                  </div>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => marcarLida(n.id)}
                  >
                    Marcar lida
                  </Button>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* ÔöÇÔöÇ Filtros ÔöÇÔöÇ */}
      <Card>
        <CardContent className="flex flex-col gap-3 p-4 sm:flex-row sm:items-center">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Buscar por n┬║ contrato ou objeto..."
              value={busca}
              onChange={(e) => setBusca(e.target.value)}
              className="pl-10"
            />
          </div>
          <div className="flex flex-wrap gap-2">
            {["todos", "pendente_assinatura", "ativo", "encerrado", "cancelado"].map(
              (s) => (
                <Button
                  key={s}
                  variant={statusFiltro === s ? "default" : "outline"}
                  size="sm"
                  onClick={() => setStatusFiltro(s)}
                >
                  {s === "todos" ? "Todos" : STATUS_LABEL[s as StatusContrato]}
                </Button>
              ),
            )}
          </div>
        </CardContent>
      </Card>

      {/* ÔöÇÔöÇ Tabela ÔöÇÔöÇ */}
      {carregando ? (
        <SkeletonTable />
      ) : filtrados.length === 0 ? (
        <EmptyState
          title="Nenhum contrato encontrado"
          description={busca || statusFiltro !== "todos" ? "Ajuste os filtros" : "Nenhum contrato recebido ainda"}
          icon={FileSignature}
        />
      ) : (
        <Card>
          <CardContent className="p-0">
            {/* Desktop */}
            <div className="hidden md:block">
              <table className="w-full">
                <thead>
                  <tr className="border-b text-left text-xs font-medium text-muted-foreground">
                    <th className="p-4">N┬║ Contrato</th>
                    <th className="p-4">Objeto</th>
                    <th className="p-4 text-right">Valor</th>
                    <th className="p-4">Vig├¬ncia</th>
                    <th className="p-4">Status</th>
                    <th className="p-4">Assinatura</th>
                    <th className="p-4">Recebido em</th>
                    <th className="p-4 text-right">A├º├Áes</th>
                  </tr>
                </thead>
                <tbody>
                  {filtrados.map((c) => {
                    const dias = c.data_fim ? calcularDiasRestantes(c.data_fim) : null;
                    return (
                      <tr
                        key={c.id}
                        className="border-b transition-colors hover:bg-muted/50 cursor-pointer"
                        onClick={() => navigate(`/contratos/${c.id}`)}
                      >
                        <td className="p-4 font-medium">{c.numero_contrato}</td>
                        <td className="max-w-48 truncate p-4 text-sm" title={c.objeto}>
                          {c.objeto}
                        </td>
                        <td className="p-4 text-right font-mono text-sm">
                          {formatarMoeda(c.valor_total)}
                        </td>
                        <td className="p-4 text-sm">
                          <div className="flex flex-col gap-1">
                            <span>
                              {c.data_inicio && new Date(c.data_inicio).toLocaleDateString("pt-BR")}
                              {" ÔåÆ "}
                              {c.data_fim && new Date(c.data_fim).toLocaleDateString("pt-BR")}
                            </span>
                            {dias !== null && c.status === "ativo" && (
                              <span className={`text-xs ${dias <= 30 ? "text-red-600 font-semibold" : dias <= 90 ? "text-amber-600" : "text-muted-foreground"}`}>
                                {dias > 0 ? `${dias} dias restantes` : "Vencido"}
                              </span>
                            )}
                          </div>
                        </td>
                        <td className="p-4">
                          <Badge variant={STATUS_VARIANT[c.status] as "default"}>
                            <span className="flex items-center gap-1">
                              {STATUS_ICON[c.status]}
                              {STATUS_LABEL[c.status]}
                            </span>
                          </Badge>
                        </td>
                        <td className="p-4">
                          {c.assinatura_digital_status && (
                            <Badge variant={ASSINATURA_VARIANT[c.assinatura_digital_status] as "default"}>
                              {ASSINATURA_LABEL[c.assinatura_digital_status] ?? c.assinatura_digital_status}
                            </Badge>
                          )}
                        </td>
                        <td className="p-4 text-sm text-muted-foreground">
                          {c.criado_em && new Date(c.criado_em).toLocaleDateString("pt-BR")}
                        </td>
                        <td className="p-4 text-right">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={(e) => {
                              e.stopPropagation();
                              navigate(`/contratos/${c.id}`);
                            }}
                          >
                            <Eye className="mr-1 h-4 w-4" />
                            Ver
                          </Button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            {/* Mobile */}
            <div className="space-y-3 p-4 md:hidden">
              {filtrados.map((c) => (
                <Card
                  key={c.id}
                  className="cursor-pointer transition-colors hover:bg-muted/30"
                  onClick={() => navigate(`/contratos/${c.id}`)}
                >
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between">
                      <span className="font-semibold">{c.numero_contrato}</span>
                      <Badge variant={STATUS_VARIANT[c.status] as "default"}>
                        {STATUS_LABEL[c.status]}
                      </Badge>
                    </div>
                    <p className="mt-1 text-sm text-muted-foreground line-clamp-2">
                      {c.objeto}
                    </p>
                    <div className="mt-2 flex items-center justify-between text-sm">
                      <span className="font-mono">{formatarMoeda(c.valor_total)}</span>
                      <ChevronRight className="h-4 w-4 text-muted-foreground" />
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/componentes/ui/card";
import { Button } from "@/componentes/ui/button";
import { Input } from "@/componentes/ui/input";
import { Separator } from "@/componentes/ui/separator";
import { EmptyState } from "@/componentes/ui/empty-state";
import { PageTransition } from "@/componentes/ui/page-transition";
import { FileOutput, Download, FileText, Building2 } from "lucide-react";
import { api } from "@/lib/api";
import { gerarDadosSICOM, downloadArquivoSICOM } from "@/servicos/exportacaoSicom";
import type { ConfigSICOM, LinhaSICOM } from "@/tipos";
import { toast } from "sonner";

interface CestaSimples {
  id: string;
  nome: string;
  status: string;
  criado_em: string;
}

export function ExportacaoSicomPage() {
  const [cestas, setCestas] = useState<CestaSimples[]>([]);
  const [cestaId, setCestaId] = useState("");
  const [carregandoCestas, setCarregandoCestas] = useState(true);

  const [config, setConfig] = useState<ConfigSICOM>({
    codigo_municipio_ibge: "",
    exercicio: new Date().getFullYear(),
    mes_referencia: new Date().getMonth() + 1,
    tipo_aquisicao: "licitacao",
    numero_processo: "",
    responsavel_nome: "",
    responsavel_cpf: "",
  });

  const [linhas, setLinhas] = useState<LinhaSICOM[]>([]);
  const [textoGerado, setTextoGerado] = useState("");
  const [gerando, setGerando] = useState(false);

  useEffect(() => {
    (async () => {
      const data = await api.get<CestaSimples[]>("/api/cestas");
      setCestas(data ?? []);
      setCarregandoCestas(false);
    })();
  }, []);

  const handleGerar = async () => {
    if (!cestaId) { toast.error("Selecione uma cesta."); return; }
    if (!config.codigo_municipio_ibge) { toast.error("Informe o c├│digo IBGE."); return; }
    if (!config.numero_processo) { toast.error("Informe o n├║mero do processo."); return; }
    if (!config.responsavel_nome || !config.responsavel_cpf) { toast.error("Informe o respons├ível."); return; }

    setGerando(true);
    try {
      const result = await gerarDadosSICOM(cestaId, config);
      setLinhas(result.linhas);
      setTextoGerado(result.texto);
      if (result.linhas.length === 0) {
        toast.info("Nenhum item encontrado na cesta para exportar.");
      } else {
        toast.success(`${result.linhas.length} itens gerados no formato SICOM.`);
      }
    } catch {
      toast.error("Erro ao gerar dados SICOM.");
    } finally {
      setGerando(false);
    }
  };

  const handleDownload = () => {
    if (!textoGerado) return;
    const nome = `SICOM_${config.codigo_municipio_ibge}_${config.exercicio}_${String(config.mes_referencia).padStart(2, "0")}.txt`;
    downloadArquivoSICOM(textoGerado, nome);
    toast.success("Arquivo baixado!");
  };

  const updateConfig = (campo: keyof ConfigSICOM, valor: any) =>
    setConfig((prev) => ({ ...prev, [campo]: valor }));

  return (
    <PageTransition>
      <div className="space-y-6">
        {/* Header */}
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <FileOutput className="h-6 w-6 text-primary" />
            Exporta├º├úo SICOM ÔÇö TCE/MG
          </h1>
          <p className="text-muted-foreground mt-1">
            Gere o arquivo de exporta├º├úo no formato exigido pelo SICOM (Sistema Informatizado de Contas dos Munic├¡pios) do Tribunal de Contas de Minas Gerais.
          </p>
        </div>

        {/* Formul├írio */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <Building2 className="h-5 w-5" />
              Dados do Munic├¡pio e Processo
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {/* Cesta */}
            <div>
              <label className="text-sm font-medium mb-1 block">Cesta de Pre├ºos</label>
              {carregandoCestas ? (
                <div className="h-10 bg-muted animate-pulse rounded" />
              ) : (
                <select
                  value={cestaId}
                  onChange={(e) => setCestaId(e.target.value)}
                  className="w-full rounded-md border bg-transparent px-3 py-2 text-sm"
                >
                  <option value="">Selecione uma cesta...</option>
                  {cestas.map((c) => (
                    <option key={c.id} value={c.id}>{c.nome} ({c.status})</option>
                  ))}
                </select>
              )}
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              <div>
                <label className="text-sm font-medium mb-1 block">C├│d. IBGE do Munic├¡pio</label>
                <Input
                  placeholder="3106200"
                  value={config.codigo_municipio_ibge}
                  onChange={(e) => updateConfig("codigo_municipio_ibge", e.target.value)}
                />
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">Exerc├¡cio</label>
                <Input
                  type="number"
                  value={config.exercicio}
                  onChange={(e) => updateConfig("exercicio", Number(e.target.value))}
                />
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">M├¬s Refer├¬ncia</label>
                <select
                  value={config.mes_referencia}
                  onChange={(e) => updateConfig("mes_referencia", Number(e.target.value))}
                  className="w-full rounded-md border bg-transparent px-3 py-2 text-sm"
                >
                  {Array.from({ length: 12 }, (_, i) => (
                    <option key={i + 1} value={i + 1}>
                      {new Date(2024, i).toLocaleString("pt-BR", { month: "long" })}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium mb-1 block">Tipo de Aquisi├º├úo</label>
                <select
                  value={config.tipo_aquisicao}
                  onChange={(e) => updateConfig("tipo_aquisicao", e.target.value)}
                  className="w-full rounded-md border bg-transparent px-3 py-2 text-sm"
                >
                  <option value="licitacao">Licita├º├úo</option>
                  <option value="dispensa">Dispensa</option>
                  <option value="inexigibilidade">Inexigibilidade</option>
                </select>
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">N├║mero do Processo</label>
                <Input
                  placeholder="001/2024"
                  value={config.numero_processo}
                  onChange={(e) => updateConfig("numero_processo", e.target.value)}
                />
              </div>
            </div>

            <Separator />

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium mb-1 block">Nome do Respons├ível</label>
                <Input
                  placeholder="Nome completo"
                  value={config.responsavel_nome}
                  onChange={(e) => updateConfig("responsavel_nome", e.target.value)}
                />
              </div>
              <div>
                <label className="text-sm font-medium mb-1 block">CPF do Respons├ível</label>
                <Input
                  placeholder="000.000.000-00"
                  value={config.responsavel_cpf}
                  onChange={(e) => updateConfig("responsavel_cpf", e.target.value)}
                />
              </div>
            </div>

            <div className="flex justify-end">
              <Button onClick={handleGerar} disabled={gerando}>
                <FileText className="h-4 w-4 mr-2" />
                {gerando ? "Gerando..." : "Gerar Arquivo SICOM"}
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Pr├®via */}
        {linhas.length > 0 && (
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle className="text-base">Pr├®via da Exporta├º├úo</CardTitle>
                <CardDescription>{linhas.length} itens gerados</CardDescription>
              </div>
              <Button onClick={handleDownload}>
                <Download className="h-4 w-4 mr-2" />
                Baixar .TXT
              </Button>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-left border-b text-muted-foreground">
                      <th className="pb-2 font-medium">#</th>
                      <th className="pb-2 font-medium">C├│digo</th>
                      <th className="pb-2 font-medium">Descri├º├úo</th>
                      <th className="pb-2 font-medium">Un.</th>
                      <th className="pb-2 font-medium text-right">Qtd</th>
                      <th className="pb-2 font-medium text-right">Vlr Unit.</th>
                      <th className="pb-2 font-medium text-right">Vlr Total</th>
                      <th className="pb-2 font-medium">CNPJ</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {linhas.map((l) => (
                      <tr key={l.sequencial} className="hover:bg-muted/50">
                        <td className="py-2 text-muted-foreground">{l.sequencial}</td>
                        <td className="py-2 font-mono text-xs">{l.codigo_item || "ÔÇö"}</td>
                        <td className="py-2 max-w-[200px] truncate">{l.descricao}</td>
                        <td className="py-2">{l.unidade}</td>
                        <td className="py-2 text-right">{l.quantidade}</td>
                        <td className="py-2 text-right font-mono">R$ {l.valor_unitario.toFixed(2)}</td>
                        <td className="py-2 text-right font-mono font-medium">R$ {l.valor_total.toFixed(2)}</td>
                        <td className="py-2 font-mono text-xs">{l.fornecedor_cnpj ?? "ÔÇö"}</td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="border-t font-medium">
                      <td colSpan={6} className="py-2 text-right">Total Geral:</td>
                      <td className="py-2 text-right font-mono">
                        R$ {linhas.reduce((s, l) => s + l.valor_total, 0).toFixed(2)}
                      </td>
                      <td />
                    </tr>
                  </tfoot>
                </table>
              </div>

              <Separator className="my-4" />

              {/* Pr├®via do texto bruto */}
              <details>
                <summary className="text-sm font-medium cursor-pointer text-muted-foreground hover:text-foreground">
                  Ver texto bruto do arquivo
                </summary>
                <pre className="mt-2 text-xs bg-muted rounded-lg p-4 overflow-x-auto max-h-60 whitespace-pre-wrap">
                  {textoGerado}
                </pre>
              </details>
            </CardContent>
          </Card>
        )}

        {!gerando && linhas.length === 0 && textoGerado === "" && (
          <EmptyState
            icon={FileOutput}
            title="Configure e gere a exporta├º├úo"
            description="Preencha os dados acima e clique em Gerar para criar o arquivo no formato SICOM/TCE-MG."
          />
        )}
      </div>
    </PageTransition>
  );
}

import { useState, useEffect, useCallback } from "react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/componentes/ui/card";
import { Button } from "@/componentes/ui/button";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  Area,
  AreaChart,
} from "recharts";
import {
  TrendingUp,
  TrendingDown,
  Minus,
  Loader2,
  Search,
  BarChart3,
  Calendar,
  Info,
} from "lucide-react";
import { toast } from "sonner";
import {
  obterHistoricoPrecos,
  listarProdutosComPrecos,
} from "@/servicos/historicoPrecos";
import type { HistoricoPrecoItem } from "@/tipos";
import { cn } from "@/lib/utils";

function moeda(v: number) {
  return v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

interface ProdutoOpcao {
  id: string;
  descricao: string;
  codigo: string | null;
  unidade_medida: { sigla: string }[] | { sigla: string } | null;
  categoria: { nome: string }[] | { nome: string } | null;
}

export function HistoricoPrecoPage() {
  const [produtos, setProdutos] = useState<ProdutoOpcao[]>([]);
  const [produtoId, setProdutoId] = useState("");
  const [meses, setMeses] = useState(12);
  const [carregandoProdutos, setCarregandoProdutos] = useState(true);
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState<HistoricoPrecoItem | null>(null);
  const [busca, setBusca] = useState("");
  const [tipoGrafico, setTipoGrafico] = useState<"line" | "area">("area");

  useEffect(() => {
    listarProdutosComPrecos()
      .then(setProdutos)
      .catch(() => toast.error("Erro ao carregar produtos"))
      .finally(() => setCarregandoProdutos(false));
  }, []);

  const handleBuscar = useCallback(async () => {
    if (!produtoId) {
      toast.warning("Selecione um produto");
      return;
    }
    setCarregando(true);
    try {
      const res = await obterHistoricoPrecos(produtoId, meses);
      setHistorico(res);
      if (res.pontos.length === 0) {
        toast.info("Nenhum dado de pre├ºo encontrado no per├¡odo selecionado");
      }
    } catch {
      toast.error("Erro ao buscar hist├│rico de pre├ºos");
    } finally {
      setCarregando(false);
    }
  }, [produtoId, meses]);

  const produtosFiltrados = busca.trim()
    ? produtos.filter(
        (p) =>
          p.descricao.toLowerCase().includes(busca.toLowerCase()) ||
          p.codigo?.toLowerCase().includes(busca.toLowerCase()),
      )
    : produtos;

  // Dados formatados para recharts
  const dadosGrafico = historico?.pontos.map((p) => ({
    mes: formatarMes(p.data),
    "M├®dia": p.valor_medio,
    "M├¡nimo": p.valor_minimo,
    "M├íximo": p.valor_maximo,
    fontes: p.total_fontes,
  })) ?? [];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-3xl font-bold tracking-tight">
          Hist├│rico de Pre├ºos
        </h2>
        <p className="text-muted-foreground">
          Acompanhe a evolu├º├úo temporal dos pre├ºos por produto
        </p>
      </div>

      {/* Sele├º├úo de produto */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Selecione o Produto</CardTitle>
          <CardDescription>
            Escolha um produto do cat├ílogo para ver a evolu├º├úo de pre├ºos
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col gap-4 md:flex-row md:items-end">
            <div className="flex-1 space-y-2">
              <label className="text-sm font-medium">Produto</label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <input
                  type="text"
                  placeholder="Filtrar produtos..."
                  className="mb-2 w-full rounded-lg border border-input bg-background py-2 pl-10 pr-4 text-sm"
                  value={busca}
                  onChange={(e) => setBusca(e.target.value)}
                />
              </div>
              <select
                className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm"
                value={produtoId}
                onChange={(e) => setProdutoId(e.target.value)}
                disabled={carregandoProdutos}
                size={5}
              >
                <option value="">Selecione...</option>
                {produtosFiltrados.map((p) => (
                  <option key={p.id} value={p.id}>
                    {p.descricao} ({Array.isArray(p.unidade_medida) ? p.unidade_medida[0]?.sigla : p.unidade_medida?.sigla ?? "UN"}) ÔÇö {Array.isArray(p.categoria) ? p.categoria[0]?.nome : p.categoria?.nome ?? ""}
                  </option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Per├¡odo</label>
              <select
                className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm"
                value={meses}
                onChange={(e) => setMeses(Number(e.target.value))}
              >
                <option value={3}>3 meses</option>
                <option value={6}>6 meses</option>
                <option value={12}>12 meses</option>
                <option value={24}>24 meses</option>
              </select>
            </div>

            <Button
              onClick={handleBuscar}
              disabled={carregando || !produtoId}
              className="shrink-0"
            >
              {carregando ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              ) : (
                <BarChart3 className="mr-2 h-4 w-4" />
              )}
              Gerar Gr├ífico
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Resultado */}
      {historico && historico.pontos.length > 0 && (
        <>
          {/* Cards resumo */}
          <div className="grid gap-4 md:grid-cols-4">
            <SummaryCard
              label="Varia├º├úo no Per├¡odo"
              valor={
                historico.variacao_12m != null
                  ? `${historico.variacao_12m > 0 ? "+" : ""}${historico.variacao_12m.toFixed(2)}%`
                  : "ÔÇö"
              }
              icone={
                historico.tendencia === "alta"
                  ? TrendingUp
                  : historico.tendencia === "baixa"
                    ? TrendingDown
                    : Minus
              }
              cor={
                historico.tendencia === "alta"
                  ? "text-red-600"
                  : historico.tendencia === "baixa"
                    ? "text-green-600"
                    : "text-muted-foreground"
              }
            />
            <SummaryCard
              label="├Ültimo Pre├ºo M├®dio"
              valor={moeda(
                historico.pontos[historico.pontos.length - 1].valor_medio,
              )}
              icone={Calendar}
              cor="text-blue-600"
            />
            <SummaryCard
              label="Menor Registrado"
              valor={moeda(
                Math.min(...historico.pontos.map((p) => p.valor_minimo)),
              )}
              icone={TrendingDown}
              cor="text-green-600"
            />
            <SummaryCard
              label="Maior Registrado"
              valor={moeda(
                Math.max(...historico.pontos.map((p) => p.valor_maximo)),
              )}
              icone={TrendingUp}
              cor="text-red-600"
            />
          </div>

          {/* Gr├ífico */}
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle className="text-lg">
                    {historico.descricao}
                  </CardTitle>
                  <CardDescription>
                    Evolu├º├úo de pre├ºos ÔÇö ├║ltimos {meses} meses ({historico.unidade})
                  </CardDescription>
                </div>
                <div className="flex gap-1">
                  <Button
                    variant={tipoGrafico === "area" ? "default" : "outline"}
                    size="sm"
                    onClick={() => setTipoGrafico("area")}
                  >
                    ├ürea
                  </Button>
                  <Button
                    variant={tipoGrafico === "line" ? "default" : "outline"}
                    size="sm"
                    onClick={() => setTipoGrafico("line")}
                  >
                    Linha
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="h-[400px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  {tipoGrafico === "area" ? (
                    <AreaChart data={dadosGrafico}>
                      <defs>
                        <linearGradient id="colorMedia" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="var(--color-primary, #3b82f6)" stopOpacity={0.3} />
                          <stop offset="95%" stopColor="var(--color-primary, #3b82f6)" stopOpacity={0} />
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" className="opacity-30" />
                      <XAxis dataKey="mes" tick={{ fontSize: 12 }} />
                      <YAxis
                        tick={{ fontSize: 12 }}
                        tickFormatter={(v) => `R$ ${v.toFixed(2)}`}
                      />
                      <Tooltip
                        formatter={(value: any, name: any) => [
                          moeda(Number(value)),
                          name,
                        ]}
                        labelFormatter={(label) => `M├¬s: ${label}`}
                      />
                      <Legend />
                      <Area
                        type="monotone"
                        dataKey="M├íximo"
                        stroke="#ef4444"
                        fill="none"
                        strokeDasharray="4 4"
                        strokeWidth={1}
                      />
                      <Area
                        type="monotone"
                        dataKey="M├®dia"
                        stroke="var(--color-primary, #3b82f6)"
                        fill="url(#colorMedia)"
                        strokeWidth={2}
                      />
                      <Area
                        type="monotone"
                        dataKey="M├¡nimo"
                        stroke="#22c55e"
                        fill="none"
                        strokeDasharray="4 4"
                        strokeWidth={1}
                      />
                    </AreaChart>
                  ) : (
                    <LineChart data={dadosGrafico}>
                      <CartesianGrid strokeDasharray="3 3" className="opacity-30" />
                      <XAxis dataKey="mes" tick={{ fontSize: 12 }} />
                      <YAxis
                        tick={{ fontSize: 12 }}
                        tickFormatter={(v) => `R$ ${v.toFixed(2)}`}
                      />
                      <Tooltip
                        formatter={(value: any, name: any) => [
                          moeda(Number(value)),
                          name,
                        ]}
                        labelFormatter={(label) => `M├¬s: ${label}`}
                      />
                      <Legend />
                      <Line
                        type="monotone"
                        dataKey="M├íximo"
                        stroke="#ef4444"
                        strokeDasharray="4 4"
                        strokeWidth={1}
                        dot={{ r: 3 }}
                      />
                      <Line
                        type="monotone"
                        dataKey="M├®dia"
                        stroke="var(--color-primary, #3b82f6)"
                        strokeWidth={2}
                        dot={{ r: 4 }}
                        activeDot={{ r: 6 }}
                      />
                      <Line
                        type="monotone"
                        dataKey="M├¡nimo"
                        stroke="#22c55e"
                        strokeDasharray="4 4"
                        strokeWidth={1}
                        dot={{ r: 3 }}
                      />
                    </LineChart>
                  )}
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>

          {/* Tabela de dados */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-lg">
                <Info className="h-4 w-4" />
                Dados Detalhados
              </CardTitle>
            </CardHeader>
            <CardContent className="overflow-x-auto p-0">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b bg-muted/50">
                    <th className="px-4 py-3 text-left font-medium">M├¬s</th>
                    <th className="px-3 py-3 text-right font-medium">M├®dia</th>
                    <th className="px-3 py-3 text-right font-medium">M├¡nimo</th>
                    <th className="px-3 py-3 text-right font-medium">M├íximo</th>
                    <th className="px-3 py-3 text-right font-medium">Fontes</th>
                    <th className="px-3 py-3 text-left font-medium">
                      Fonte Principal
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {historico.pontos.map((p) => (
                    <tr key={p.data} className="border-b hover:bg-muted/30">
                      <td className="px-4 py-2 font-medium">
                        {formatarMes(p.data)}
                      </td>
                      <td className="px-3 py-2 text-right">
                        {moeda(p.valor_medio)}
                      </td>
                      <td className="px-3 py-2 text-right text-green-600">
                        {moeda(p.valor_minimo)}
                      </td>
                      <td className="px-3 py-2 text-right text-red-600">
                        {moeda(p.valor_maximo)}
                      </td>
                      <td className="px-3 py-2 text-right text-muted-foreground">
                        {p.total_fontes}
                      </td>
                      <td className="px-3 py-2 text-muted-foreground">
                        {p.fonte_principal ?? "ÔÇö"}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

// ÔöÇÔöÇ Componentes internos ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function SummaryCard({
  label,
  valor,
  icone: Icone,
  cor,
}: {
  label: string;
  valor: string;
  icone: React.ComponentType<{ className?: string }>;
  cor: string;
}) {
  return (
    <Card>
      <CardContent className="flex items-center gap-4 py-4">
        <div className={cn("rounded-lg bg-muted p-2", cor)}>
          <Icone className="h-5 w-5" />
        </div>
        <div>
          <div className="text-sm text-muted-foreground">{label}</div>
          <div className="text-lg font-bold">{valor}</div>
        </div>
      </CardContent>
    </Card>
  );
}

function formatarMes(data: string): string {
  const [ano, mes] = data.split("-");
  const meses = [
    "Jan",
    "Fev",
    "Mar",
    "Abr",
    "Mai",
    "Jun",
    "Jul",
    "Ago",
    "Set",
    "Out",
    "Nov",
    "Dez",
  ];
  return `${meses[parseInt(mes, 10) - 1]}/${ano.slice(2)}`;
}

import { useState } from "react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/componentes/ui/card";
import { Button } from "@/componentes/ui/button";
import { Badge } from "@/componentes/ui/badge";
import { Input } from "@/componentes/ui/input";
import { Separator } from "@/componentes/ui/separator";
import {
  Shield,
  FileText,
  CheckCircle2,
  XCircle,
  Download,
  Key,
  Smartphone,
  AlertTriangle,
  ClipboardList,
  UserCheck,
  Lock,
  Eye,
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useConsentimentos, useSolicitacoesLgpd } from "@/hooks/useFase17";
import {
  DOCUMENTOS_LGPD,
  TIPOS_SOLICITACAO_LGPD,
  gerarSegredoTOTP,
  gerarOtpAuthURI,
  ativar2FA,
  desativar2FA,
  gerarRelatorioDadosPessoais,
} from "@/servicos/lgpd";
import type { TipoConsentimento, TipoSolicitacaoLgpd } from "@/tipos";

type AbaLgpd = "consentimentos" | "solicitacoes" | "2fa" | "dados";

export function LGPDPage() {
  const { servidor } = useAuth();
  const [aba, setAba] = useState<AbaLgpd>("consentimentos");
  const [descricaoSolicitacao, setDescricaoSolicitacao] = useState("");
  const [totp2FA, setTotp2FA] = useState(false);
  const [segredoQR, setSegredoQR] = useState<string | null>(null);

  const {
    consentimentos,
    pendentes,
    carregando: _carregandoConsent,
    registrar,
    revogar,
  } = useConsentimentos(servidor?.id);

  const {
    solicitacoes,
    carregando: carregandoSolic,
    criar: criarSolicitacao,
  } = useSolicitacoesLgpd(servidor?.id);

  const handleAtivar2FA = async () => {
    if (!servidor) return;
    const segredo = gerarSegredoTOTP();
    await ativar2FA(servidor.id, segredo);
    setSegredoQR(segredo);
    setTotp2FA(true);
  };

  const handleDesativar2FA = async () => {
    if (!servidor) return;
    await desativar2FA(servidor.id);
    setTotp2FA(false);
    setSegredoQR(null);
  };

  const handleBaixarDados = async () => {
    if (!servidor) return;
    try {
      const dados = await gerarRelatorioDadosPessoais(servidor.id);
      const blob = new Blob([JSON.stringify(dados, null, 2)], {
        type: "application/json",
      });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `meus_dados_${new Date().toISOString().slice(0, 10)}.json`;
      link.click();
      URL.revokeObjectURL(url);
    } catch (e) {
      alert("Erro ao exportar dados");
    }
  };

  const abas: Array<{ id: AbaLgpd; label: string; icon: React.ReactNode }> = [
    { id: "consentimentos", label: "Consentimentos", icon: <FileText className="h-4 w-4" /> },
    { id: "solicitacoes", label: "Solicita├º├Áes", icon: <ClipboardList className="h-4 w-4" /> },
    { id: "2fa", label: "Autentica├º├úo 2FA", icon: <Key className="h-4 w-4" /> },
    { id: "dados", label: "Meus Dados", icon: <Eye className="h-4 w-4" /> },
  ];

  return (
    <div className="space-y-6">
      {/* Cabe├ºalho */}
      <div>
        <h1 className="text-2xl font-bold flex items-center gap-2">
          <Shield className="h-6 w-6" />
          Privacidade e LGPD
        </h1>
        <p className="text-sm text-muted-foreground mt-1">
          Lei Geral de Prote├º├úo de Dados Pessoais ÔÇö Gerencie seus consentimentos, dados e seguran├ºa
        </p>
      </div>

      {/* Alerta de pend├¬ncias */}
      {pendentes.length > 0 && (
        <Card className="border-amber-200 bg-amber-50">
          <CardContent className="py-4 flex items-center gap-3">
            <AlertTriangle className="h-5 w-5 text-amber-600 shrink-0" />
            <div className="flex-1">
              <p className="font-medium text-amber-800">
                Voc├¬ possui {pendentes.length} consentimento(s) obrigat├│rio(s) pendente(s)
              </p>
              <p className="text-sm text-amber-700">
                {pendentes.map((p) => DOCUMENTOS_LGPD[p].titulo).join(", ")}
              </p>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Abas */}
      <div className="flex gap-1 border-b">
        {abas.map((a) => (
          <Button
            key={a.id}
            variant={aba === a.id ? "default" : "ghost"}
            size="sm"
            className="rounded-b-none"
            onClick={() => setAba(a.id)}
          >
            {a.icon}
            <span className="ml-1">{a.label}</span>
          </Button>
        ))}
      </div>

      {/* Conte├║do das abas */}
      {aba === "consentimentos" && (
        <div className="space-y-3">
          {(Object.entries(DOCUMENTOS_LGPD) as [TipoConsentimento, typeof DOCUMENTOS_LGPD["termos_uso"]][]).map(
            ([tipo, doc]) => {
              const consentimento = consentimentos.find(
                (c) => c.tipo === tipo && c.aceito && !c.revogado_em,
              );
              const aceito = !!consentimento;

              return (
                <Card
                  key={tipo}
                  className={aceito ? "border-green-200" : doc.obrigatorio ? "border-red-200" : ""}
                >
                  <CardContent className="py-4">
                    <div className="flex items-start justify-between gap-3">
                      <div className="flex-1">
                        <div className="flex items-center gap-2">
                          {aceito ? (
                            <CheckCircle2 className="h-5 w-5 text-green-600" />
                          ) : (
                            <XCircle className="h-5 w-5 text-gray-400" />
                          )}
                          <span className="font-medium">{doc.titulo}</span>
                          {doc.obrigatorio && (
                            <Badge variant="destructive" className="text-xs">
                              Obrigat├│rio
                            </Badge>
                          )}
                          <Badge variant="outline" className="text-xs">
                            v{doc.versao}
                          </Badge>
                        </div>
                        <p className="text-sm text-muted-foreground mt-1 ml-7">
                          {doc.descricao}
                        </p>
                        {consentimento && (
                          <p className="text-xs text-muted-foreground mt-1 ml-7">
                            Aceito em: {new Date(consentimento.aceito_em!).toLocaleString("pt-BR")}
                          </p>
                        )}
                      </div>
                      <div className="flex gap-2 shrink-0">
                        {aceito ? (
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => revogar(tipo)}
                            disabled={doc.obrigatorio}
                          >
                            Revogar
                          </Button>
                        ) : (
                          <Button size="sm" onClick={() => registrar(tipo, true)}>
                            <CheckCircle2 className="h-4 w-4 mr-1" />
                            Aceitar
                          </Button>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              );
            },
          )}
        </div>
      )}

      {aba === "solicitacoes" && (
        <div className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Nova Solicita├º├úo</CardTitle>
              <CardDescription>
                Exercer seus direitos como titular dos dados conforme a LGPD
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                {(Object.entries(TIPOS_SOLICITACAO_LGPD) as [TipoSolicitacaoLgpd, typeof TIPOS_SOLICITACAO_LGPD["exclusao"]][]).map(
                  ([tipo, info]) => (
                    <Card
                      key={tipo}
                      className="cursor-pointer hover:bg-accent/50 transition-colors"
                      onClick={() =>
                        criarSolicitacao(tipo, descricaoSolicitacao || undefined)
                      }
                    >
                      <CardContent className="py-4">
                        <p className="font-medium text-sm">{info.titulo}</p>
                        <p className="text-xs text-muted-foreground mt-1">
                          {info.descricao}
                        </p>
                        <Badge variant="outline" className="text-xs mt-2">
                          {info.artigo}
                        </Badge>
                      </CardContent>
                    </Card>
                  ),
                )}
              </div>
              <Input
                placeholder="Descri├º├úo adicional (opcional)..."
                value={descricaoSolicitacao}
                onChange={(e) => setDescricaoSolicitacao(e.target.value)}
              />
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Hist├│rico de Solicita├º├Áes</CardTitle>
            </CardHeader>
            <CardContent>
              {carregandoSolic ? (
                <p className="text-muted-foreground">Carregando...</p>
              ) : solicitacoes.length === 0 ? (
                <p className="text-muted-foreground text-center py-8">
                  Nenhuma solicita├º├úo registrada
                </p>
              ) : (
                <div className="space-y-2">
                  {solicitacoes.map((s) => (
                    <div key={s.id} className="flex items-center gap-3 p-3 rounded-lg border">
                      <Badge
                        variant="outline"
                        className={
                          s.status === "concluida"
                            ? "bg-green-100 text-green-700"
                            : s.status === "recusada"
                            ? "bg-red-100 text-red-700"
                            : s.status === "em_andamento"
                            ? "bg-blue-100 text-blue-700"
                            : "bg-amber-100 text-amber-700"
                        }
                      >
                        {s.status}
                      </Badge>
                      <div className="flex-1">
                        <p className="text-sm font-medium">
                          {TIPOS_SOLICITACAO_LGPD[s.tipo]?.titulo ?? s.tipo}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {new Date(s.criado_em).toLocaleString("pt-BR")}
                        </p>
                      </div>
                      {s.resposta && (
                        <Badge variant="secondary" className="text-xs">
                          Respondida
                        </Badge>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {aba === "2fa" && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <Smartphone className="h-5 w-5" />
              Autentica├º├úo de Dois Fatores (2FA)
            </CardTitle>
            <CardDescription>
              Proteja sua conta com autentica├º├úo TOTP via Google Authenticator, Authy ou similar
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {totp2FA || segredoQR ? (
              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <CheckCircle2 className="h-6 w-6 text-green-600" />
                  <div>
                    <p className="font-medium">2FA ativado</p>
                    <p className="text-sm text-muted-foreground">
                      Sua conta est├í protegida com autentica├º├úo de dois fatores
                    </p>
                  </div>
                </div>

                {segredoQR && (
                  <Card className="bg-blue-50 border-blue-200">
                    <CardContent className="py-4 space-y-3">
                      <p className="text-sm font-medium text-blue-800">
                        Escaneie o QR Code no seu aplicativo autenticador:
                      </p>
                      <div className="p-4 bg-white rounded-lg border text-center">
                        <code className="text-xs break-all">
                          {gerarOtpAuthURI(servidor?.email ?? "", segredoQR)}
                        </code>
                      </div>
                      <p className="text-xs text-blue-700">
                        Ou insira manualmente o segredo: <strong>{segredoQR}</strong>
                      </p>
                    </CardContent>
                  </Card>
                )}

                <Button variant="destructive" size="sm" onClick={handleDesativar2FA}>
                  <Lock className="h-4 w-4 mr-2" />
                  Desativar 2FA
                </Button>
              </div>
            ) : (
              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <XCircle className="h-6 w-6 text-gray-400" />
                  <div>
                    <p className="font-medium">2FA desativado</p>
                    <p className="text-sm text-muted-foreground">
                      Recomendamos ativar para maior seguran├ºa da sua conta
                    </p>
                  </div>
                </div>
                <Button onClick={handleAtivar2FA}>
                  <Key className="h-4 w-4 mr-2" />
                  Ativar Autentica├º├úo 2FA
                </Button>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {aba === "dados" && (
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2">
              <UserCheck className="h-5 w-5" />
              Meus Dados Pessoais
            </CardTitle>
            <CardDescription>
              Visualize e exporte seus dados pessoais conforme Art. 18 da LGPD
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {servidor && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <div>
                    <p className="text-xs text-muted-foreground">Nome</p>
                    <p className="text-sm font-medium">{servidor.nome}</p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground">E-mail</p>
                    <p className="text-sm font-medium">{servidor.email}</p>
                  </div>
                </div>
                <div className="space-y-2">
                  <div>
                    <p className="text-xs text-muted-foreground">CPF</p>
                    <p className="text-sm font-medium">{servidor.cpf ?? "N├úo informado"}</p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground">Matr├¡cula</p>
                    <p className="text-sm font-medium">{servidor.matricula ?? "N├úo informada"}</p>
                  </div>
                </div>
              </div>
            )}

            <Separator />

            <div className="flex gap-3">
              <Button variant="outline" onClick={handleBaixarDados}>
                <Download className="h-4 w-4 mr-2" />
                Exportar Meus Dados (JSON)
              </Button>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

export default LGPDPage;

import { useState, useEffect } from "react";
import {
  BarChart3,
  Users,
  ShoppingCart,
  FileText,
  Database,
  Package,
  Clock,
  Loader2,
  RefreshCw,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useAuth } from "@/hooks/useAuth";
import { buscarMetricasUso, atualizarMetricasUso } from "@/servicos/metricasUso";
import type { MetricasUsoMunicipio } from "@/tipos";

export function MetricasUsoPage() {
  const { servidor } = useAuth();
  const municipioId = servidor?.secretaria?.municipio_id;

  const [metricas, setMetricas] = useState<MetricasUsoMunicipio | null>(null);
  const [carregando, setCarregando] = useState(true);
  const [atualizando, setAtualizando] = useState(false);

  useEffect(() => {
    carregar();
  }, [municipioId]);

  async function carregar() {
    if (!municipioId) return;
    setCarregando(true);
    try {
      const m = await buscarMetricasUso(municipioId);
      setMetricas(m);
    } catch {
      /* toast */
    } finally {
      setCarregando(false);
    }
  }

  async function handleAtualizar() {
    if (!municipioId) return;
    setAtualizando(true);
    try {
      const m = await atualizarMetricasUso(municipioId);
      setMetricas(m);
    } finally {
      setAtualizando(false);
    }
  }

  if (carregando) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="h-8 w-8 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <BarChart3 className="h-6 w-6 text-blue-600" />
            M├®tricas de Uso
          </h1>
          <p className="text-gray-500 mt-1">
            Acompanhe o consumo do seu munic├¡pio.
          </p>
        </div>
        <button
          onClick={handleAtualizar}
          disabled={atualizando}
          className="flex items-center gap-1.5 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 transition text-sm"
        >
          <RefreshCw className={cn("h-4 w-4", atualizando && "animate-spin")} />
          Atualizar
        </button>
      </div>

      {/* Vis├úo geral de uso */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <MetricCard
          titulo="Usu├írios"
          valor={metricas?.total_usuarios ?? 0}
          icone={Users}
          cor="blue"
        />
        <MetricCard
          titulo="Cestas de Pre├ºos"
          valor={metricas?.total_cestas ?? 0}
          icone={ShoppingCart}
          cor="green"
        />
        <MetricCard
          titulo="Cota├º├Áes / m├¬s"
          valor={metricas?.cotacoes_ultimo_mes ?? 0}
          icone={FileText}
          cor="purple"
        />
      </div>

      {/* Cards detalhados */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <MetricCard
          titulo="Produtos no Cat├ílogo"
          valor={metricas?.total_produtos_catalogo ?? 0}
          icone={Package}
          cor="orange"
        />
        <MetricCard
          titulo="Cota├º├Áes (total)"
          valor={metricas?.total_cotacoes ?? 0}
          icone={FileText}
          cor="blue"
        />
        <MetricCard
          titulo="Cestas no ├║ltimo m├¬s"
          valor={metricas?.cestas_ultimo_mes ?? 0}
          icone={ShoppingCart}
          cor="green"
        />
        <MetricCard
          titulo="Armazenamento"
          valor={`${metricas?.armazenamento_mb?.toFixed(1) ?? "0.0"} MB`}
          icone={Database}
          cor="purple"
        />
      </div>

      {/* ├Ültimo acesso */}
      {metricas?.ultimo_acesso && (
        <div className="flex items-center gap-2 text-sm text-gray-400">
          <Clock className="h-4 w-4" />
          ├Ültima atualiza├º├úo: {new Date(metricas.atualizado_em).toLocaleString("pt-BR")}
        </div>
      )}
    </div>
  );
}

// ÔöÇÔöÇÔöÇ Metric Card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function MetricCard({
  titulo,
  valor,
  icone: Icon,
  cor,
}: {
  titulo: string;
  valor: number | string;
  icone: React.ElementType;
  cor: "blue" | "green" | "purple" | "orange";
}) {
  const corMap = {
    blue: "bg-blue-50 text-blue-600",
    green: "bg-green-50 text-green-600",
    purple: "bg-purple-50 text-purple-600",
    orange: "bg-orange-50 text-orange-600",
  };

  return (
    <div className="bg-white rounded-xl border p-4">
      <div className="flex items-center gap-2 mb-2">
        <div className={cn("p-1.5 rounded", corMap[cor])}>
          <Icon className="h-3.5 w-3.5" />
        </div>
        <span className="text-xs text-gray-500 font-medium">{titulo}</span>
      </div>
      <p className="text-xl font-bold text-gray-900">{valor}</p>
    </div>
  );
}

