  type EstatisticasGlobais,
  type PeriodoPesquisa,
} from "@/servicos/pesquisaRapida";

// ÔöÇÔöÇ Formatadores ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function moeda(valor: number | null | undefined) {
  if (valor == null || valor === 0) return "ÔÇö";
  return valor.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}
function dataFormatada(iso: string | null) {
  if (!iso) return "ÔÇö";
  return new Date(iso).toLocaleDateString("pt-BR");
}

// ÔöÇÔöÇ ├ìcones das fontes ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const ICONE_FONTE: Record<string, React.ReactNode> = {
  pncp: <Globe className="h-3.5 w-3.5" />,
  painel_precos: <Globe className="h-3.5 w-3.5" />,
  tce: <MapPin className="h-3.5 w-3.5" />,
  bps: <Heart className="h-3.5 w-3.5" />,
  sinapi: <HardHat className="h-3.5 w-3.5" />,
  conab: <Wheat className="h-3.5 w-3.5" />,
  ceasa: <Apple className="h-3.5 w-3.5" />,
  cmed: <Pill className="h-3.5 w-3.5" />,
};

// ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù
// Ôòæ  Componente Principal                                Ôòæ
// ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ

export function PesquisaRapidaPage() {
  // ÔöÇÔöÇ Autocomplete ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const autocomplete = useAutocompleteProdutos(300);
  const [produtoSelecionado, setProdutoSelecionado] = useState<
    Pick<ProdutoCatalogo, "id" | "descricao" | "codigo_catmat"> | null
  >(null);
  const [showSugestoes, setShowSugestoes] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // ÔöÇÔöÇ Busca em todas as fontes ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const {
    pncp, painel, tce, multiTCE,
    bps, sinapi, conab, ceasa, cmed,
    buscarTodas, limparTodas, carregando,
  } = useBuscaTodasFontes();

  // ÔöÇÔöÇ Filtros ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const [periodo, setPeriodo] = useState<PeriodoPesquisa>("12m");
  const [dataInicio, setDataInicio] = useState(() => calcularDataInicioPeriodo("12m"));
  const [dataFim, setDataFim] = useState(new Date().toISOString().slice(0, 10));
  const [uf, setUf] = useState("");
  const [regiao, setRegiao] = useState("");
  const [showFiltros, setShowFiltros] = useState(false);

  // ÔöÇÔöÇ Resultados unificados ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const [abaResultado, setAbaResultado] = useState("todos");
  const [buscaRealizada, setBuscaRealizada] = useState(false);

  // Atualizar dataInicio quando mudar periodo
  useEffect(() => {
    if (periodo !== "custom") {
      const novaData = calcularDataInicioPeriodo(periodo);
      queueMicrotask(() => setDataInicio(novaData));
    }
  }, [periodo]);

  // ÔöÇÔöÇ Resultados unificados e deduplicados ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const resultadosUnificados = useMemo(() => {
    const todos: ResultadoPesquisaUnificado[] = [
      ...normalizarParaUnificado(pncp.dados, "pncp"),
      ...normalizarParaUnificado(painel.dados, "painel_precos"),
      ...normalizarParaUnificado([...tce.dados, ...multiTCE.dados], "tce"),
      ...normalizarParaUnificado(bps.dados, "bps"),
      ...normalizarParaUnificado(sinapi.dados, "sinapi"),
      ...normalizarParaUnificado(conab.dados, "conab"),
      ...normalizarParaUnificado(ceasa.dados, "ceasa"),
      ...normalizarParaUnificado(cmed.dados, "cmed"),
    ];
    return deduplicarResultados(todos);
  }, [pncp.dados, painel.dados, tce.dados, multiTCE.dados, bps.dados, sinapi.dados, conab.dados, ceasa.dados, cmed.dados]);

  // ÔöÇÔöÇ Filtrar por UF/regi├úo se selecionado ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const resultadosFiltrados = useMemo(() => {
    let filtered = resultadosUnificados;
    if (uf) {
      filtered = filtered.filter((r) => r.uf === uf || !r.uf);
    }
    if (regiao && REGIOES_BRASIL[regiao]) {
      const ufsRegiao = new Set(REGIOES_BRASIL[regiao]);
      filtered = filtered.filter((r) => !r.uf || ufsRegiao.has(r.uf as UF));
    }
    return filtered;
  }, [resultadosUnificados, uf, regiao]);

  // ÔöÇÔöÇ Estat├¡sticas ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const estatisticas = useMemo<EstatisticasGlobais>(
    () => calcularEstatisticasPesquisa(resultadosFiltrados),
    [resultadosFiltrados]
  );

  // ÔöÇÔöÇ Fontes dispon├¡veis (para abas) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const fontesComDados = useMemo(() => {
    const tipos = new Set(resultadosFiltrados.map((r) => r.fonte_tipo));
    return Array.from(tipos);
  }, [resultadosFiltrados]);

  // ÔöÇÔöÇ Resultados por aba ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const resultadosDaAba = useMemo(() => {
    if (abaResultado === "todos") return resultadosFiltrados;
    return resultadosFiltrados.filter((r) => r.fonte_tipo === abaResultado);
  }, [resultadosFiltrados, abaResultado]);

  // ÔöÇÔöÇ Sele├º├úo para envio ├á cesta ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const [selecionados, setSelecionados] = useState<Set<string>>(new Set());
  const [drawerEnvio, setDrawerEnvio] = useState(false);

  const toggleSelecionado = useCallback((id: string) => {
    setSelecionados((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, []);

  const selecionarTodos = useCallback(() => {
    setSelecionados(new Set(resultadosDaAba.map((r) => r.id)));
  }, [resultadosDaAba]);

  const limparSelecao = useCallback(() => {
    setSelecionados(new Set());
  }, []);

  const itensSelecionados = useMemo(
    () => resultadosFiltrados.filter((r) => selecionados.has(r.id)),
    [resultadosFiltrados, selecionados]
  );

  // ÔöÇÔöÇ Buscar ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleBuscar = useCallback(async () => {
    const termoFinal = produtoSelecionado?.descricao ?? autocomplete.termo;
    if (!termoFinal.trim()) return;

    setSelecionados(new Set());
    setBuscaRealizada(true);

    const filtro: FiltroFonte = {
      termo: termoFinal.trim(),
      uf: uf || undefined,
      dataInicio: dataInicio || undefined,
      dataFim: dataFim || undefined,
      limite: 50,
    };
    await buscarTodas(filtro);
  }, [produtoSelecionado, autocomplete.termo, uf, dataInicio, dataFim, buscarTodas]);

  // ÔöÇÔöÇ Selecionar produto do autocomplete ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleSelecionarProduto = useCallback(
    (produto: Pick<ProdutoCatalogo, "id" | "descricao" | "codigo_catmat">) => {
      setProdutoSelecionado(produto);
      autocomplete.setTermo(produto.descricao);
      setShowSugestoes(false);
      // Auto-buscar ao selecionar
      setTimeout(() => {
        setBuscaRealizada(true);
        const filtro: FiltroFonte = {
          termo: produto.descricao,
          uf: uf || undefined,
          dataInicio: dataInicio || undefined,
          dataFim: dataFim || undefined,
          limite: 50,
        };
        buscarTodas(filtro);
      }, 100);
    },
    [uf, dataInicio, dataFim, buscarTodas, autocomplete]
  );

  // ÔöÇÔöÇ Limpar tudo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleLimpar = useCallback(() => {
    autocomplete.limpar();
    setProdutoSelecionado(null);
    limparTodas();
    setSelecionados(new Set());
    setBuscaRealizada(false);
    setAbaResultado("todos");
  }, [autocomplete, limparTodas]);

  return (
    <div className="space-y-6">
      {/* ÔöÇÔöÇ Cabe├ºalho ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <div>
        <h2 className="text-3xl font-bold tracking-tight">Pesquisa R├ípida de Pre├ºos</h2>
        <p className="text-muted-foreground">
          Consulta direta de pre├ºos sem necessidade de cadastrar cesta ÔÇö resultados de todas as 8 fontes integradas
        </p>
      </div>

      {/* ÔöÇÔöÇ Barra de busca + autocomplete ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <Card>
        <CardContent className="pt-6 space-y-4">
          <div className="flex gap-2 relative">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-3.5 h-4 w-4 text-muted-foreground" />
              <Input
                ref={inputRef}
                placeholder="Digite o produto para consulta r├ípida (ex: Arroz Tipo 1 5kg)..."
                value={autocomplete.termo}
                onChange={(e) => {
                  autocomplete.setTermo(e.target.value);
                  setProdutoSelecionado(null);
                  setShowSugestoes(true);
                }}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    setShowSugestoes(false);
                    handleBuscar();
                  }
                  if (e.key === "Escape") setShowSugestoes(false);
                }}
                onFocus={() => {
                  if (autocomplete.sugestoes.length > 0) setShowSugestoes(true);
                }}
                className="pl-10 h-12 text-base"
              />
              {/* Dropdown autocomplete */}
              {showSugestoes && autocomplete.sugestoes.length > 0 && (
                <div className="absolute z-50 top-full mt-1 left-0 right-0 bg-background border rounded-lg shadow-lg max-h-60 overflow-y-auto">
                  {autocomplete.sugestoes.map((s) => (
                    <button
                      key={s.id}
                      className="w-full text-left px-4 py-2.5 hover:bg-muted/50 transition-colors flex items-center gap-3"
                      onClick={() => handleSelecionarProduto(s)}
                    >
                      <Package className="h-4 w-4 text-muted-foreground shrink-0" />
                      <div>
                        <div className="text-sm">{s.descricao}</div>
                        {s.codigo_catmat && (
                          <span className="text-xs text-muted-foreground">
                            CATMAT: {s.codigo_catmat}
                          </span>
                        )}
                      </div>
                    </button>
                  ))}
                </div>
              )}
              {autocomplete.buscando && (
                <Loader2 className="absolute right-3 top-3.5 h-4 w-4 animate-spin text-muted-foreground" />
              )}
            </div>

            <Button
              variant="outline"
              size="icon"
              className="h-12 w-12"
              onClick={() => setShowFiltros(!showFiltros)}
              title="Filtros avan├ºados"
            >
              <Filter className="h-4 w-4" />
            </Button>
            <Button
              onClick={handleBuscar}
              disabled={carregando || !autocomplete.termo.trim()}
              className="h-12 px-6"
            >
              {carregando ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : (
                <Search className="h-4 w-4 mr-2" />
              )}
              Pesquisar
            </Button>
            {buscaRealizada && (
              <Button variant="ghost" size="icon" className="h-12 w-12" onClick={handleLimpar}>
                <X className="h-4 w-4" />
              </Button>
            )}
          </div>

          {/* Produto selecionado */}
          {produtoSelecionado && (
            <div className="flex items-center gap-2 text-sm">
              <Badge variant="secondary" className="flex items-center gap-1">
                <Package className="h-3 w-3" />
                {produtoSelecionado.descricao}
                {produtoSelecionado.codigo_catmat && (
                  <span className="text-muted-foreground ml-1">
                    ({produtoSelecionado.codigo_catmat})
                  </span>
                )}
              </Badge>
              <button
                onClick={() => {
                  setProdutoSelecionado(null);
                  autocomplete.setTermo("");
                  inputRef.current?.focus();
                }}
                className="text-muted-foreground hover:text-foreground"
              >
                <X className="h-3.5 w-3.5" />
              </button>
            </div>
          )}

          {/* ÔöÇÔöÇ Filtros avan├ºados ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
          {showFiltros && (
            <div className="p-4 bg-muted/50 rounded-lg space-y-4">
              {/* Per├¡odo */}
              <div className="space-y-2">
                <label className="text-xs font-medium text-muted-foreground">Per├¡odo</label>
                <div className="flex gap-2">
                  {(
                    [
                      { value: "3m", label: "3 meses" },
                      { value: "6m", label: "6 meses" },
                      { value: "12m", label: "12 meses" },
                      { value: "custom", label: "Personalizado" },
                    ] as { value: PeriodoPesquisa; label: string }[]
                  ).map((p) => (
                    <Button
                      key={p.value}
                      variant={periodo === p.value ? "default" : "outline"}
                      size="sm"
                      className="text-xs h-8"
                      onClick={() => setPeriodo(p.value)}
                    >
                      {p.label}
                    </Button>
                  ))}
                </div>
                {periodo === "custom" && (
                  <div className="flex gap-3 mt-2">
                    <div className="flex flex-col gap-1">
                      <label className="text-[10px] text-muted-foreground">Data in├¡cio</label>
                      <Input
                        type="date"
                        value={dataInicio}
                        onChange={(e) => setDataInicio(e.target.value)}
                        className="w-40 h-8 text-xs"
                      />
                    </div>
                    <div className="flex flex-col gap-1">
                      <label className="text-[10px] text-muted-foreground">Data fim</label>
                      <Input
                        type="date"
                        value={dataFim}
                        onChange={(e) => setDataFim(e.target.value)}
                        className="w-40 h-8 text-xs"
                      />
                    </div>
                  </div>
                )}
              </div>

              <Separator />

              {/* Regi├úo / UF */}
              <div className="flex flex-wrap gap-4">
                <div className="flex flex-col gap-1">
                  <label className="text-xs font-medium text-muted-foreground">Regi├úo</label>
                  <select
                    value={regiao}
                    onChange={(e) => setRegiao(e.target.value)}
                    className="h-8 rounded-md border border-input bg-background px-3 text-xs"
                  >
                    <option value="">Todas as regi├Áes</option>
                    {Object.keys(REGIOES_BRASIL).map((r) => (
                      <option key={r} value={r}>
                        {r}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="flex flex-col gap-1">
                  <label className="text-xs font-medium text-muted-foreground">UF</label>
                  <select
                    value={uf}
                    onChange={(e) => setUf(e.target.value)}
                    className="h-8 rounded-md border border-input bg-background px-3 text-xs"
                  >
                    <option value="">Todas</option>
                    {(regiao && REGIOES_BRASIL[regiao]
                      ? REGIOES_BRASIL[regiao]
                      : [...UFS_BRASIL]
                    ).map((u) => (
                      <option key={u} value={u}>
                        {u}
                      </option>
                    ))}
                  </select>
                </div>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* ÔöÇÔöÇ Estat├¡sticas Globais ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {buscaRealizada && !carregando && resultadosFiltrados.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
          <StatCard
            label="Total"
            valor={String(estatisticas.total)}
            icone={<BarChart3 className="h-4 w-4 text-muted-foreground" />}
          />
          <StatCard
            label="Menor pre├ºo"
            valor={moeda(estatisticas.menor_preco)}
            icone={<TrendingDown className="h-4 w-4 text-green-600" />}
            destaque="green"
          />
          <StatCard
            label="Maior pre├ºo"
            valor={moeda(estatisticas.maior_preco)}
            icone={<TrendingUp className="h-4 w-4 text-red-500" />}
          />
          <StatCard
            label="M├®dia"
            valor={moeda(estatisticas.media)}
            icone={<BarChart3 className="h-4 w-4 text-blue-600" />}
          />
          <StatCard
            label="Mediana"
            valor={moeda(estatisticas.mediana)}
            icone={<BarChart3 className="h-4 w-4 text-purple-600" />}
            destaque="purple"
          />
        </div>
      )}

      {/* ÔöÇÔöÇ Estat├¡sticas por Fonte ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {buscaRealizada && !carregando && estatisticas.por_fonte.length > 0 && (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-base">Comparativo por Fonte</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b text-left text-muted-foreground">
                    <th className="p-2">Fonte</th>
                    <th className="p-2 text-right">Qtd</th>
                    <th className="p-2 text-right">Menor</th>
                    <th className="p-2 text-right">Maior</th>
                    <th className="p-2 text-right">M├®dia</th>
                    <th className="p-2 text-right">Mediana</th>
                  </tr>
                </thead>
                <tbody>
                  {estatisticas.por_fonte.map((ef) => (
                    <tr key={ef.fonte_tipo} className="border-b hover:bg-muted/30">
                      <td className="p-2 flex items-center gap-2">
                        {ICONE_FONTE[ef.fonte_tipo]}
                        <span className="font-medium">{ef.fonte_nome}</span>
                      </td>
                      <td className="p-2 text-right">
                        <Badge variant="secondary" className="text-[10px]">
                          {ef.quantidade}
                        </Badge>
                      </td>
                      <td className="p-2 text-right text-green-700 dark:text-green-400 font-medium">
                        {moeda(ef.menor_preco)}
                      </td>
                      <td className="p-2 text-right text-red-600 dark:text-red-400">
                        {moeda(ef.maior_preco)}
                      </td>
                      <td className="p-2 text-right font-medium">{moeda(ef.media)}</td>
                      <td className="p-2 text-right">{moeda(ef.mediana)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      )}

      {/* ÔöÇÔöÇ Resultados detalhados ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {buscaRealizada && (
        <Card>
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-base flex items-center gap-2">
                Resultados
                {resultadosFiltrados.length > 0 && (
                  <Badge variant="secondary">{resultadosFiltrados.length}</Badge>
                )}
              </CardTitle>
              {selecionados.size > 0 && (
                <div className="flex items-center gap-2">
                  <Badge variant="default">
                    {selecionados.size} selecionado(s)
                  </Badge>
                  <Button
                    size="sm"
                    className="h-8"
                    onClick={() => setDrawerEnvio(true)}
                  >
                    <Send className="h-3.5 w-3.5 mr-1.5" />
                    Enviar para Cesta
                  </Button>
                </div>
              )}
            </div>
          </CardHeader>
          <CardContent>
            {carregando ? (
              <div className="flex items-center justify-center py-12 text-muted-foreground">
                <Loader2 className="h-5 w-5 animate-spin mr-2" />
                Consultando todas as fontes...
              </div>
            ) : resultadosFiltrados.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
                <Search className="h-8 w-8 mb-2 opacity-40" />
                <p className="text-sm">
                  {buscaRealizada
                    ? "Nenhum resultado encontrado. Tente ampliar os filtros."
                    : "Selecione um produto do cat├ílogo para pesquisar automaticamente."}
                </p>
              </div>
            ) : (
              <>
                <Tabs value={abaResultado} onValueChange={setAbaResultado}>
                  <div className="flex items-center justify-between mb-3">
                    <TabsList className="flex-wrap justify-start h-auto gap-1">
                      <TabsTrigger value="todos" className="text-xs">
                        Todos
                        <Badge variant="secondary" className="ml-1 text-[10px] px-1.5 py-0">
                          {resultadosFiltrados.length}
                        </Badge>
                      </TabsTrigger>
                      {fontesComDados.map((tipo) => {
                        const count = resultadosFiltrados.filter((r) => r.fonte_tipo === tipo).length;
                        return (
                          <TabsTrigger key={tipo} value={tipo} className="flex items-center gap-1 text-xs">
                            {ICONE_FONTE[tipo]}
                            {nomeFonteLegivel(tipo)}
                            <Badge variant="secondary" className="text-[10px] px-1.5 py-0">
                              {count}
                            </Badge>
                          </TabsTrigger>
                        );
                      })}
                    </TabsList>

                    <div className="flex gap-1 ml-2 shrink-0">
                      <Button variant="ghost" size="sm" className="text-xs h-7" onClick={selecionarTodos}>
                        Sel. todos
                      </Button>
                      {selecionados.size > 0 && (
                        <Button variant="ghost" size="sm" className="text-xs h-7" onClick={limparSelecao}>
                          Limpar
                        </Button>
                      )}
                    </div>
                  </div>
                </Tabs>

                {/* Tabela unificada */}
                <TabelaResultadosUnificada
                  dados={resultadosDaAba}
                  selecionados={selecionados}
                  onToggle={toggleSelecionado}
                />
              </>
            )}
          </CardContent>
        </Card>
      )}

      {/* ÔöÇÔöÇ Drawer: Enviar para Cesta ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <DrawerEnviarParaCesta
        aberto={drawerEnvio}
        onClose={() => setDrawerEnvio(false)}
        itens={itensSelecionados}
        produtoId={produtoSelecionado?.id ?? null}
        produtoDescricao={produtoSelecionado?.descricao ?? autocomplete.termo}
        onEnviado={() => {
          setSelecionados(new Set());
          setDrawerEnvio(false);
        }}
      />
    </div>
  );
}

// ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù
// Ôòæ  Sub-componentes                                    Ôòæ
// ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ

function StatCard({
  label,
  valor,
  icone,
  destaque,
}: {
  label: string;
  valor: string;
  icone: React.ReactNode;
  destaque?: "green" | "purple";
}) {
  return (
    <Card className={destaque === "green" ? "border-green-200 dark:border-green-800" : ""}>
      <CardContent className="pt-4 pb-3 px-4">
        <div className="flex items-center gap-2 mb-1">
          {icone}
          <span className="text-xs text-muted-foreground">{label}</span>
        </div>
        <p
          className={`text-lg font-bold ${
            destaque === "green"
              ? "text-green-700 dark:text-green-400"
              : destaque === "purple"
                ? "text-purple-700 dark:text-purple-400"
                : ""
          }`}
        >
          {valor}
        </p>
      </CardContent>
    </Card>
  );
}

// ÔöÇÔöÇ Tabela unificada ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

function TabelaResultadosUnificada({
  dados,
  selecionados,
  onToggle,
}: {
  dados: ResultadoPesquisaUnificado[];
  selecionados: Set<string>;
  onToggle: (id: string) => void;
}) {
  // Ordenar por valor unit├írio crescente
  const ordenados = useMemo(
    () => [...dados].sort((a, b) => a.valor_unitario - b.valor_unitario),
    [dados]
  );

  if (ordenados.length === 0) {
    return (
      <div className="flex items-center justify-center py-8 text-muted-foreground text-sm">
        Nenhum resultado nesta fonte.
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <table className="w-full text-sm">
        <thead>
          <tr className="border-b text-left text-muted-foreground">
            <th className="p-2 w-8"></th>
            <th className="p-2">Fonte</th>
            <th className="p-2">Descri├º├úo</th>
            <th className="p-2">├ôrg├úo</th>
            <th className="p-2">UF</th>
            <th className="p-2 text-right">Valor Unit.</th>
            <th className="p-2">Data</th>
          </tr>
        </thead>
        <tbody>
          {ordenados.map((d, i) => {
            const sel = selecionados.has(d.id);
            const isMenor = i === 0;
            return (
              <tr
                key={d.id}
                className={`border-b hover:bg-muted/50 cursor-pointer transition-colors ${
                  sel ? "bg-primary/5" : ""
                } ${isMenor ? "bg-green-50/50 dark:bg-green-950/20" : ""}`}
                onClick={() => onToggle(d.id)}
              >
                <td className="p-2">
                  <input
                    type="checkbox"
                    checked={sel}
                    onChange={() => onToggle(d.id)}
                    className="rounded"
                  />
                </td>
                <td className="p-2">
                  <Badge variant="outline" className="text-[10px] flex items-center gap-1 w-fit">
                    {ICONE_FONTE[d.fonte_tipo]}
                    {d.fonte_detalhe}
                  </Badge>
                </td>
                <td className="p-2 max-w-[220px] truncate" title={d.descricao_item}>
                  {d.descricao_item}
                </td>
                <td className="p-2 max-w-[150px] truncate" title={d.orgao}>
                  {d.orgao || "ÔÇö"}
                </td>
                <td className="p-2">{d.uf || "ÔÇö"}</td>
                <td className="p-2 text-right font-medium">
                  {isMenor && (
                    <TrendingDown className="inline h-3.5 w-3.5 text-green-600 mr-1" />
                  )}
                  {moeda(d.valor_unitario)}
                </td>
                <td className="p-2">{dataFormatada(d.data_referencia)}</td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

// ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù
// Ôòæ  Drawer: Enviar para Cesta                          Ôòæ
// ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ

function DrawerEnviarParaCesta({
  aberto,
  onClose,
  itens,
  produtoId,
  produtoDescricao,
  onEnviado,
}: {
  aberto: boolean;
  onClose: () => void;
  itens: ResultadoPesquisaUnificado[];
  produtoId: string | null;
  produtoDescricao: string;
  onEnviado: () => void;
}) {
  const fontes = useFontes();
  const [cestas, setCestas] = useState<
    Pick<import("@/tipos").CestaPrecos, "id" | "descricao_objeto" | "status" | "criado_em">[]
  >([]);
  const [cestaId, setCestaId] = useState("");
  const [quantidade, setQuantidade] = useState("1");
  const [carregandoCestas, setCarregandoCestas] = useState(false);
  const [enviando, setEnviando] = useState(false);
  const [enviado, setEnviado] = useState(false);
  const [erro, setErro] = useState("");

  // Carregar cestas ativas quando abre
  useEffect(() => {
    if (!aberto) return;
    setCarregandoCestas(true);
    setEnviado(false);
    setErro("");
    listarCestasAtivas()
      .then((data) => {
        setCestas(data);
        if (data.length > 0 && !cestaId) setCestaId(data[0].id);
      })
      .catch(() => setCestas([]))
      .finally(() => setCarregandoCestas(false));
  }, [aberto]);

  const handleEnviar = useCallback(async () => {
    if (!cestaId || !produtoId || itens.length === 0) {
      setErro(
        !produtoId
          ? "Selecione um produto do cat├ílogo antes de enviar."
          : !cestaId
            ? "Selecione uma cesta de destino."
            : "Nenhum pre├ºo selecionado."
      );
      return;
    }

    setEnviando(true);
    setErro("");
    try {
      await enviarParaCesta({
        cestaId,
        produtoId,
        quantidade: parseInt(quantidade) || 1,
        resultados: itens,
        fontes,
      });
      setEnviado(true);
      setTimeout(() => onEnviado(), 1500);
    } catch (e) {
      setErro(e instanceof Error ? e.message : "Erro ao enviar para cesta.");
    } finally {
      setEnviando(false);
    }
  }, [cestaId, produtoId, itens, fontes, quantidade, onEnviado]);

  const estatsSel = useMemo(() => calcularEstatisticasPesquisa(itens), [itens]);

  return (
    <Drawer open={aberto} onOpenChange={(v) => !v && onClose()}>
      <DrawerContent side="right">
        <DrawerHeader>
          <DrawerTitle className="flex items-center gap-2">
            <Send className="h-5 w-5" />
            Enviar para Cesta
          </DrawerTitle>
        </DrawerHeader>
        <DrawerBody>
          <div className="space-y-5">
            {/* Resumo */}
            <div className="p-4 bg-muted/50 rounded-lg space-y-2">
              <p className="text-sm font-medium">
                {produtoDescricao}
              </p>
              <div className="flex flex-wrap gap-2 text-xs text-muted-foreground">
                <span>{itens.length} pre├ºo(s) selecionado(s)</span>
                <span>ÔÇó</span>
                <span>Menor: {moeda(estatsSel.menor_preco)}</span>
                <span>ÔÇó</span>
                <span>M├®dia: {moeda(estatsSel.media)}</span>
                <span>ÔÇó</span>
                <span>Mediana: {moeda(estatsSel.mediana)}</span>
              </div>
              <div className="flex flex-wrap gap-1 mt-2">
                {estatsSel.por_fonte.map((ef) => (
                  <Badge key={ef.fonte_tipo} variant="outline" className="text-[10px]">
                    {ef.fonte_nome}: {ef.quantidade}
                  </Badge>
                ))}
              </div>
            </div>

            {/* Cesta destino */}
            <div className="space-y-2">
              <label className="text-sm font-medium">Cesta de destino</label>
              {carregandoCestas ? (
                <div className="flex items-center gap-2 text-sm text-muted-foreground py-2">
                  <Loader2 className="h-4 w-4 animate-spin" />
                  Carregando cestas...
                </div>
              ) : cestas.length === 0 ? (
                <div className="text-sm text-muted-foreground py-2">
                  <AlertCircle className="h-4 w-4 inline mr-1" />
                  Nenhuma cesta ativa encontrada. Crie uma cesta antes de enviar.
                </div>
              ) : (
                <select
                  value={cestaId}
                  onChange={(e) => setCestaId(e.target.value)}
                  className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                >
                  {cestas.map((c) => (
                    <option key={c.id} value={c.id}>
                      {c.descricao_objeto} ({c.status === "rascunho" ? "Rascunho" : "Em andamento"})
                    </option>
                  ))}
                </select>
              )}
            </div>

            {/* Quantidade */}
            <div className="space-y-2">
              <label className="text-sm font-medium">Quantidade</label>
              <Input
                type="number"
                min="1"
                value={quantidade}
                onChange={(e) => setQuantidade(e.target.value)}
                className="w-32"
              />
            </div>

            {/* Lista de pre├ºos que ser├úo enviados */}
            <div className="space-y-2">
              <label className="text-sm font-medium">Pre├ºos a transferir</label>
              <div className="max-h-48 overflow-y-auto border rounded-lg">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="border-b text-muted-foreground">
                      <th className="p-2 text-left">Fonte</th>
                      <th className="p-2 text-left">├ôrg├úo</th>
                      <th className="p-2 text-right">Valor</th>
                      <th className="p-2">Data</th>
                    </tr>
                  </thead>
                  <tbody>
                    {itens.map((it) => (
                      <tr key={it.id} className="border-b">
                        <td className="p-2">
                          <Badge variant="outline" className="text-[9px]">
                            {it.fonte_detalhe}
                          </Badge>
                        </td>
                        <td className="p-2 max-w-[120px] truncate">{it.orgao}</td>
                        <td className="p-2 text-right font-medium">{moeda(it.valor_unitario)}</td>
                        <td className="p-2">{dataFormatada(it.data_referencia)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Erros e sucesso */}
            {erro && (
              <div className="flex items-center gap-2 text-sm text-destructive">
                <AlertCircle className="h-4 w-4" />
                {erro}
              </div>
            )}
            {enviado && (
              <div className="flex items-center gap-2 text-sm text-green-600">
                <CheckCircle2 className="h-4 w-4" />
                Pre├ºos enviados com sucesso para a cesta!
              </div>
            )}

            {/* Bot├Áes */}
            <div className="flex justify-end gap-2 pt-2 border-t">
              <Button variant="outline" onClick={onClose}>
                Cancelar
              </Button>
              <Button
                onClick={handleEnviar}
                disabled={enviando || !cestaId || !produtoId || itens.length === 0 || enviado}
              >
                {enviando ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : (
                  <ArrowRightCircle className="h-4 w-4 mr-2" />
                )}
                Enviar {itens.length} pre├ºo(s)
              </Button>
            </div>
          </div>
        </DrawerBody>
      </DrawerContent>
    </Drawer>
  );
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
// Drawer de Corre├º├úo Monet├íria ÔÇö Fase 8
// Aplica├º├úo de IPCA/IGP-M na cesta, pr├®via de valores, relat├│rio por item
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import { useCallback, useEffect, useState } from "react";
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerBody,
} from "@/componentes/ui/drawer";
import { Button } from "@/componentes/ui/button";
import { Badge } from "@/componentes/ui/badge";
import { Input } from "@/componentes/ui/input";
import { Card, CardContent } from "@/componentes/ui/card";
import { Separator } from "@/componentes/ui/separator";
import {
  TrendingUp,
  Calculator,
  Loader2,
  AlertCircle,
  CheckCircle2,
  Trash2,
  BarChart3,
  Download,
  Info,
  Calendar,
} from "lucide-react";
import type { CestaPrecos, TipoIndice, ResumoCorrecaoCesta } from "@/tipos";
import {
  useIndicesCorrecao,
  useImportacaoIndices,
  useCorrecaoCesta,
} from "@/hooks/useCorrecaoMonetaria";
import {
  NOME_INDICE,
  DESCRICAO_INDICE,
  formatarPeriodo,
  formatarPercentual,
} from "@/servicos/correcaoMonetaria";

// ÔöÇÔöÇ Formatadores ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function moeda(valor: number | null | undefined) {
  if (valor == null || valor === 0) return "ÔÇö";
  return valor.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

// ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù
// Ôòæ  Export principal                                    Ôòæ
// ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ

interface CorrecaoMonetariaDrawerProps {
  cesta: CestaPrecos;
  aberto: boolean;
  onClose: () => void;
  onAtualizado: () => void;
}

export function CorrecaoMonetariaDrawer({
  cesta,
  aberto,
  onClose,
  onAtualizado,
}: CorrecaoMonetariaDrawerProps) {
  // ÔöÇÔöÇ Hooks ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const indicesHook = useIndicesCorrecao();
  const importacao = useImportacaoIndices();
  const correcao = useCorrecaoCesta();

  // ÔöÇÔöÇ Estado local ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const [tipoIndice, setTipoIndice] = useState<TipoIndice>(
    cesta.tipo_correcao !== "nenhuma" ? (cesta.tipo_correcao as TipoIndice) : "ipca",
  );
  const [dataBase, setDataBase] = useState(
    cesta.data_base_correcao ?? new Date().toISOString().slice(0, 10),
  );
  const [aba, setAba] = useState<"aplicar" | "indices" | "relatorio">(
    cesta.correcao_aplicada_em ? "relatorio" : "aplicar",
  );
  const [ultimoIpca, setUltimoIpca] = useState<string | null>(null);
  const [ultimoIgpm, setUltimoIgpm] = useState<string | null>(null);

  const jaCorrigida = !!cesta.correcao_aplicada_em;

  // ÔöÇÔöÇ Carregar info de ├║ltimos ├¡ndices ao abrir ÔöÇÔöÇ
  useEffect(() => {
    if (!aberto) return;
    indicesHook.buscarUltimo("ipca").then((idx) => {
      if (idx) setUltimoIpca(formatarPeriodo(idx.ano, idx.mes));
    });
    indicesHook.buscarUltimo("igpm").then((idx) => {
      if (idx) setUltimoIgpm(formatarPeriodo(idx.ano, idx.mes));
    });
  }, [aberto]);

  // ÔöÇÔöÇ Aplicar corre├º├úo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleAplicar = useCallback(async () => {
    const res = await correcao.aplicar(cesta.id, tipoIndice, dataBase);
    if (res) {
      setAba("relatorio");
      onAtualizado();
    }
  }, [cesta.id, tipoIndice, dataBase, correcao, onAtualizado]);

  // ÔöÇÔöÇ Remover corre├º├úo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleRemover = useCallback(async () => {
    if (!confirm("Remover toda corre├º├úo monet├íria desta cesta? Os pre├ºos voltar├úo aos valores originais.")) return;
    await correcao.remover(cesta.id);
    setAba("aplicar");
    onAtualizado();
  }, [cesta.id, correcao, onAtualizado]);

  // ÔöÇÔöÇ Importar ├¡ndices ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleImportar = useCallback(
    async (tipo: TipoIndice) => {
      await importacao.importar(tipo);
      // Recarregar info
      const idx = await indicesHook.buscarUltimo(tipo);
      if (idx) {
        if (tipo === "ipca") setUltimoIpca(formatarPeriodo(idx.ano, idx.mes));
        else setUltimoIgpm(formatarPeriodo(idx.ano, idx.mes));
      }
    },
    [importacao, indicesHook],
  );

  return (
    <Drawer open={aberto} onOpenChange={(v) => !v && onClose()}>
      <DrawerContent side="right" className="w-full max-w-2xl">
        <DrawerHeader>
          <DrawerTitle className="flex items-center gap-2">
            <Calculator className="h-5 w-5" />
            Corre├º├úo Monet├íria
          </DrawerTitle>
        </DrawerHeader>
        <DrawerBody>
          <div className="space-y-5">
            {/* Info da cesta */}
            <div className="p-3 bg-muted/50 rounded-lg text-sm space-y-1">
              <p className="font-medium">{cesta.descricao_objeto}</p>
              <div className="flex flex-wrap gap-2 text-xs text-muted-foreground">
                <span>Data: {new Date(cesta.data + "T00:00:00").toLocaleDateString("pt-BR")}</span>
                {jaCorrigida && (
                  <>
                    <span>ÔÇó</span>
                    <Badge variant="success" className="text-[10px]">
                      <CheckCircle2 className="h-3 w-3 mr-1" />
                      Corre├º├úo aplicada ({NOME_INDICE[cesta.tipo_correcao as TipoIndice] ?? cesta.tipo_correcao})
                    </Badge>
                    {cesta.data_base_correcao && (
                      <span>Data-base: {new Date(cesta.data_base_correcao + "T00:00:00").toLocaleDateString("pt-BR")}</span>
                    )}
                  </>
                )}
              </div>
            </div>

            {/* Abas */}
            <div className="flex gap-1 rounded-lg border p-1">
              {(
                [
                  { value: "aplicar", label: "Aplicar Corre├º├úo" },
                  { value: "indices", label: "├ìndices" },
                  { value: "relatorio", label: "Relat├│rio" },
                ] as { value: typeof aba; label: string }[]
              ).map((tab) => (
                <button
                  key={tab.value}
                  type="button"
                  className={`flex-1 rounded-md px-3 py-1.5 text-xs font-medium transition ${
                    aba === tab.value
                      ? "bg-primary text-primary-foreground"
                      : "hover:bg-accent"
                  }`}
                  onClick={() => setAba(tab.value)}
                >
                  {tab.label}
                </button>
              ))}
            </div>

            {/* ÔöÇÔöÇÔöÇÔöÇ ABA: Aplicar Corre├º├úo ÔöÇÔöÇÔöÇÔöÇ */}
            {aba === "aplicar" && (
              <div className="space-y-5">
                {/* Tipo de ├¡ndice */}
                <div className="space-y-2">
                  <label className="text-sm font-medium">├ìndice de Corre├º├úo</label>
                  <div className="grid grid-cols-2 gap-3">
                    {(["ipca", "igpm"] as TipoIndice[]).map((tipo) => {
                      const selecionado = tipoIndice === tipo;
                      const ultimoDisp = tipo === "ipca" ? ultimoIpca : ultimoIgpm;
                      return (
                        <button
                          key={tipo}
                          type="button"
                          className={`p-3 rounded-lg border text-left transition ${
                            selecionado
                              ? "border-primary bg-primary/5 ring-1 ring-primary"
                              : "hover:border-primary/50"
                          }`}
                          onClick={() => setTipoIndice(tipo)}
                        >
                          <div className="font-medium text-sm">{NOME_INDICE[tipo]}</div>
                          <p className="text-[10px] text-muted-foreground mt-1 line-clamp-2">
                            {DESCRICAO_INDICE[tipo]}
                          </p>
                          <div className="mt-2 flex items-center justify-between">
                            <Badge
                              variant={ultimoDisp ? "secondary" : "warning"}
                              className="text-[10px]"
                            >
                              {ultimoDisp
                                ? `├Ültimo: ${ultimoDisp}`
                                : "Sem dados"}
                            </Badge>
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>

                {/* Data-base */}
                <div className="space-y-2">
                  <label className="text-sm font-medium flex items-center gap-1">
                    <Calendar className="h-3.5 w-3.5" />
                    Data-base (valor corrigido at├®)
                  </label>
                  <Input
                    type="date"
                    value={dataBase}
                    onChange={(e) => setDataBase(e.target.value)}
                    className="w-48"
                  />
                  <p className="text-[10px] text-muted-foreground">
                    O valor de cada pre├ºo ser├í atualizado da data de contrata├º├úo at├® esta data-base.
                  </p>
                </div>

                {/* Info */}
                <div className="flex items-start gap-2 p-3 bg-blue-50 dark:bg-blue-950/30 rounded-lg text-sm">
                  <Info className="h-4 w-4 shrink-0 text-blue-600 mt-0.5" />
                  <div className="text-xs text-blue-800 dark:text-blue-300">
                    <p className="font-medium mb-1">Como funciona a corre├º├úo</p>
                    <p>
                      Cada pre├ºo ├® multiplicado pelo fator acumulado do ├¡ndice escolhido,
                      do m├¬s seguinte ├á data de refer├¬ncia at├® o m├¬s da data-base.
                      A f├│rmula usa encadeamento: fator = ╬á(1 + i/100).
                    </p>
                  </div>
                </div>

                {/* Erros */}
                {correcao.erro && (
                  <div className="flex items-center gap-2 text-sm text-destructive">
                    <AlertCircle className="h-4 w-4" />
                    {correcao.erro}
                  </div>
                )}

                {/* Bot├Áes */}
                <div className="flex gap-2 pt-2 border-t">
                  {jaCorrigida && (
                    <Button
                      variant="outline"
                      onClick={handleRemover}
                      disabled={correcao.removendo}
                      className="text-destructive"
                    >
                      {correcao.removendo ? (
                        <Loader2 className="h-4 w-4 animate-spin mr-2" />
                      ) : (
                        <Trash2 className="h-4 w-4 mr-2" />
                      )}
                      Remover Corre├º├úo
                    </Button>
                  )}
                  <Button
                    onClick={handleAplicar}
                    disabled={correcao.aplicando || !dataBase}
                    className="flex-1"
                  >
                    {correcao.aplicando ? (
                      <Loader2 className="h-4 w-4 animate-spin mr-2" />
                    ) : (
                      <Calculator className="h-4 w-4 mr-2" />
                    )}
                    {jaCorrigida ? "Reaplicar Corre├º├úo" : "Aplicar Corre├º├úo"}
                  </Button>
                </div>
              </div>
            )}

            {/* ÔöÇÔöÇÔöÇÔöÇ ABA: ├ìndices ÔöÇÔöÇÔöÇÔöÇ */}
            {aba === "indices" && (
              <AbaIndices
                indicesHook={indicesHook}
                importacao={importacao}
                onImportar={handleImportar}
                ultimoIpca={ultimoIpca}
                ultimoIgpm={ultimoIgpm}
              />
            )}

            {/* ÔöÇÔöÇÔöÇÔöÇ ABA: Relat├│rio ÔöÇÔöÇÔöÇÔöÇ */}
            {aba === "relatorio" && (
              <AbaRelatorio
                resumo={correcao.resumo}
                jaCorrigida={jaCorrigida}
                cesta={cesta}
              />
            )}
          </div>
        </DrawerBody>
      </DrawerContent>
    </Drawer>
  );
}

// ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù
// Ôòæ  Sub: Aba ├ìndices                                    Ôòæ
// ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ

function AbaIndices({
  indicesHook,
  importacao,
  onImportar,
  ultimoIpca,
  ultimoIgpm,
}: {
  indicesHook: ReturnType<typeof useIndicesCorrecao>;
  importacao: ReturnType<typeof useImportacaoIndices>;
  onImportar: (tipo: TipoIndice) => Promise<void>;
  ultimoIpca: string | null;
  ultimoIgpm: string | null;
}) {
  const [tipoVer, setTipoVer] = useState<TipoIndice>("ipca");
  const [anoVer, setAnoVer] = useState(new Date().getFullYear());

  // Carregar ├¡ndices ao mudar tipo/ano
  useEffect(() => {
    indicesHook.carregar(tipoVer, anoVer, anoVer);
  }, [tipoVer, anoVer]);

  // Carregar logs
  useEffect(() => {
    importacao.carregarLogs();
  }, []);

  return (
    <div className="space-y-5">
      {/* Status + Importar */}
      <div className="grid grid-cols-2 gap-3">
        {(["ipca", "igpm"] as TipoIndice[]).map((tipo) => {
          const ultimo = tipo === "ipca" ? ultimoIpca : ultimoIgpm;
          return (
            <Card key={tipo}>
              <CardContent className="pt-4 pb-3 px-4 space-y-2">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">{NOME_INDICE[tipo]}</span>
                  <Badge variant={ultimo ? "secondary" : "warning"} className="text-[10px]">
                    {ultimo ?? "Sem dados"}
                  </Badge>
                </div>
                <Button
                  size="sm"
                  variant="outline"
                  className="w-full text-xs"
                  onClick={() => onImportar(tipo)}
                  disabled={importacao.importando}
                >
                  {importacao.importando && importacao.resultado?.tipo === tipo ? (
                    <Loader2 className="h-3 w-3 animate-spin mr-1" />
                  ) : (
                    <Download className="h-3 w-3 mr-1" />
                  )}
                  Importar desde 2015
                </Button>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Resultado da importa├º├úo */}
      {importacao.resultado && (
        <div
          className={`flex items-center gap-2 text-sm p-2 rounded-lg ${
            importacao.resultado.erro
              ? "bg-destructive/10 text-destructive"
              : "bg-green-50 dark:bg-green-950/30 text-green-700 dark:text-green-400"
          }`}
        >
          {importacao.resultado.erro ? (
            <AlertCircle className="h-4 w-4" />
          ) : (
            <CheckCircle2 className="h-4 w-4" />
          )}
          {importacao.resultado.erro
            ? `Erro: ${importacao.resultado.erro}`
            : `${importacao.resultado.importados} registros de ${NOME_INDICE[importacao.resultado.tipo]} importados com sucesso.`}
        </div>
      )}

      <Separator />

      {/* Visualizar ├¡ndices */}
      <div className="space-y-3">
        <div className="flex items-center gap-3">
          <select
            value={tipoVer}
            onChange={(e) => setTipoVer(e.target.value as TipoIndice)}
            className="h-8 rounded-md border border-input bg-background px-2 text-xs"
          >
            <option value="ipca">IPCA</option>
            <option value="igpm">IGP-M</option>
          </select>
          <div className="flex gap-1">
            <Button
              size="sm"
              variant="ghost"
              className="h-8 px-2"
              onClick={() => setAnoVer((a) => a - 1)}
            >
              ÔùÇ
            </Button>
            <span className="text-sm font-medium py-1 px-2">{anoVer}</span>
            <Button
              size="sm"
              variant="ghost"
              className="h-8 px-2"
              onClick={() => setAnoVer((a) => a + 1)}
              disabled={anoVer >= new Date().getFullYear()}
            >
              ÔûÂ
            </Button>
          </div>
        </div>

        {indicesHook.carregando ? (
          <div className="flex items-center justify-center py-6 text-muted-foreground">
            <Loader2 className="h-4 w-4 animate-spin mr-2" />
            Carregando ├¡ndices...
          </div>
        ) : indicesHook.indices.length === 0 ? (
          <div className="text-center py-6 text-sm text-muted-foreground">
            <BarChart3 className="h-8 w-8 mx-auto mb-2 opacity-40" />
            Nenhum ├¡ndice dispon├¡vel para {anoVer}.
            <br />
            Clique em "Importar" acima para buscar dados.
          </div>
        ) : (
          <div className="rounded-md border overflow-hidden">
            <table className="w-full text-xs">
              <thead>
                <tr className="border-b bg-muted/50 text-muted-foreground">
                  <th className="px-3 py-2 text-left">M├¬s</th>
                  <th className="px-3 py-2 text-right">Var. Mensal (%)</th>
                  <th className="px-3 py-2 text-right">Acum. 12m (%)</th>
                </tr>
              </thead>
              <tbody>
                {indicesHook.indices.map((idx) => (
                  <tr key={`${idx.ano}-${idx.mes}`} className="border-b last:border-0 hover:bg-muted/30">
                    <td className="px-3 py-1.5 font-medium">
                      {formatarPeriodo(idx.ano, idx.mes)}
                    </td>
                    <td className="px-3 py-1.5 text-right">
                      <span
                        className={
                          idx.valor > 0
                            ? "text-red-600 dark:text-red-400"
                            : idx.valor < 0
                              ? "text-green-600 dark:text-green-400"
                              : ""
                        }
                      >
                        {idx.valor > 0 ? "+" : ""}
                        {idx.valor.toFixed(2)}
                      </span>
                    </td>
                    <td className="px-3 py-1.5 text-right">
                      {idx.acumulado_12m != null ? (
                        <span
                          className={
                            idx.acumulado_12m > 0
                              ? "text-red-600 dark:text-red-400"
                              : idx.acumulado_12m < 0
                                ? "text-green-600 dark:text-green-400"
                                : ""
                          }
                        >
                          {idx.acumulado_12m > 0 ? "+" : ""}
                          {idx.acumulado_12m.toFixed(2)}
                        </span>
                      ) : (
                        "ÔÇö"
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Logs de importa├º├úo */}
      {importacao.logs.length > 0 && (
        <>
          <Separator />
          <div className="space-y-2">
            <h4 className="text-xs font-medium text-muted-foreground">├Ültimas importa├º├Áes</h4>
            <div className="space-y-1">
              {importacao.logs.slice(0, 5).map((log) => (
                <div
                  key={log.id}
                  className="flex items-center justify-between text-[10px] px-2 py-1 bg-muted/30 rounded"
                >
                  <span>
                    {NOME_INDICE[log.tipo]} ÔÇö {log.registros_importados} registros
                    {log.periodo_inicio && ` (${log.periodo_inicio} a ${log.periodo_fim})`}
                  </span>
                  <span className="text-muted-foreground">
                    {new Date(log.criado_em).toLocaleString("pt-BR")}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

// ÔòöÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòù
// Ôòæ  Sub: Aba Relat├│rio                                  Ôòæ
// ÔòÜÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòØ

function AbaRelatorio({
