      )}
    </div>
  );
}

import { useCallback, useEffect, useState } from "react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/componentes/ui/card";
import { Button } from "@/componentes/ui/button";
import { Input } from "@/componentes/ui/input";
import {
  Shield,
  ShieldCheck,
  ShieldOff,
  Loader2,
  AlertCircle,
  CheckCircle2,
  Copy,
  QrCode,
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import {
  gerarSegredo,
  gerarOtpauthUri,
  verificarTOTP,
  ativar2FA,
  desativar2FA,
  verificar2FAAtivo,
  obterSegredo2FA,
} from "@/servicos/totp";

type Etapa = "status" | "setup" | "verificar" | "desativar";

export function SegurancaDoisFatoresTab() {
  const { usuario, servidor } = useAuth();
  const [etapa, setEtapa] = useState<Etapa>("status");
  const [ativo, setAtivo] = useState(false);
  const [carregando, setCarregando] = useState(true);
  const [segredo, setSegredo] = useState("");
  const [qrDataUrl, setQrDataUrl] = useState("");
  const [codigo, setCodigo] = useState("");
  const [erro, setErro] = useState<string | null>(null);
  const [sucesso, setSucesso] = useState<string | null>(null);
  const [processando, setProcessando] = useState(false);

  // Verificar status ao montar
  useEffect(() => {
    verificar2FAAtivo()
      .then(setAtivo)
      .finally(() => setCarregando(false));
  }, []);

  // Iniciar configura├º├úo 2FA
  const iniciarSetup = useCallback(async () => {
    setErro(null);
    setSucesso(null);
    const novoSegredo = gerarSegredo();
    setSegredo(novoSegredo);

    const email = usuario?.email ?? "usuario@licitanest.com";
    const uri = gerarOtpauthUri(email, novoSegredo);

    // Gerar QR code como data URL usando canvas (sem depend├¬ncia externa)
    try {
      const qrUrl = await gerarQRCodeDataUrl(uri);
      setQrDataUrl(qrUrl);
    } catch {
      setQrDataUrl("");
    }

    setEtapa("setup");
  }, [usuario]);

  // Verificar c├│digo e ativar
  const confirmarAtivacao = useCallback(async () => {
    setErro(null);
    if (codigo.length !== 6 || !/^\d{6}$/.test(codigo)) {
      setErro("Digite os 6 d├¡gitos do aplicativo autenticador.");
      return;
    }

    setProcessando(true);
    const valido = await verificarTOTP(segredo, codigo);
    if (!valido) {
      setErro("C├│digo inv├ílido. Tente novamente.");
      setProcessando(false);
      return;
    }

    const { erro: erroSalvar } = await ativar2FA(segredo, servidor?.id ?? "");
    setProcessando(false);

    if (erroSalvar) {
      setErro(erroSalvar);
      return;
    }

    setAtivo(true);
    setSucesso("Autentica├º├úo de dois fatores ativada com sucesso!");
    setEtapa("status");
    setCodigo("");
  }, [codigo, segredo, servidor]);

  // Desativar 2FA
  const confirmarDesativacao = useCallback(async () => {
    setErro(null);
    if (codigo.length !== 6 || !/^\d{6}$/.test(codigo)) {
      setErro("Digite o c├│digo atual para confirmar a desativa├º├úo.");
      return;
    }

    setProcessando(true);
    // Verificar c├│digo antes de desativar
    const secret = await obterSegredo2FA();
    if (secret) {
      const valido = await verificarTOTP(secret, codigo);
      if (!valido) {
        setErro("C├│digo inv├ílido.");
        setProcessando(false);
        return;
      }
    }

    const { erro: erroDesativar } = await desativar2FA(servidor?.id ?? "");
    setProcessando(false);

    if (erroDesativar) {
      setErro(erroDesativar);
      return;
    }

    setAtivo(false);
    setSucesso("Autentica├º├úo de dois fatores desativada.");
    setEtapa("status");
    setCodigo("");
  }, [codigo, usuario, servidor]);

  const copiarSegredo = () => {
    navigator.clipboard.writeText(segredo);
    setSucesso("Chave copiada!");
    setTimeout(() => setSucesso(null), 2000);
  };

  if (carregando) {
    return (
      <Card>
        <CardContent className="flex items-center justify-center py-12">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Shield className="h-5 w-5" />
          Autentica├º├úo de Dois Fatores (2FA)
        </CardTitle>
        <CardDescription>
          Proteja sua conta com verifica├º├úo TOTP via aplicativo autenticador
          (Google Authenticator, Authy, etc.)
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Mensagens */}
        {erro && (
          <div className="flex items-center gap-2 rounded-lg border border-destructive/50 bg-destructive/10 px-3 py-2.5 text-sm text-destructive">
            <AlertCircle className="h-4 w-4 shrink-0" />
            <span>{erro}</span>
          </div>
        )}
        {sucesso && (
          <div className="flex items-center gap-2 rounded-lg border border-emerald-500/30 bg-emerald-50 px-3 py-2.5 text-sm text-emerald-700">
            <CheckCircle2 className="h-4 w-4 shrink-0" />
            <span>{sucesso}</span>
          </div>
        )}

        {/* ÔöÇÔöÇ Status ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
        {etapa === "status" && (
          <div className="space-y-4">
            <div className="flex items-center gap-3 rounded-lg border p-4">
              {ativo ? (
                <>
                  <ShieldCheck className="h-8 w-8 text-emerald-600" />
                  <div>
                    <p className="font-medium text-emerald-700">2FA Ativo</p>
                    <p className="text-sm text-muted-foreground">
                      Sua conta est├í protegida com autentica├º├úo de dois fatores.
                    </p>
                  </div>
                </>
              ) : (
                <>
                  <ShieldOff className="h-8 w-8 text-amber-500" />
                  <div>
                    <p className="font-medium text-amber-700">2FA Inativo</p>
                    <p className="text-sm text-muted-foreground">
                      Recomendamos ativar a autentica├º├úo de dois fatores para maior
                      seguran├ºa.
                    </p>
                  </div>
                </>
              )}
            </div>

            {ativo ? (
              <Button
                variant="outline"
                className="text-destructive"
                onClick={() => {
                  setCodigo("");
                  setErro(null);
                  setSucesso(null);
                  setEtapa("desativar");
                }}
              >
                <ShieldOff className="mr-2 h-4 w-4" />
                Desativar 2FA
              </Button>
            ) : (
              <Button onClick={iniciarSetup}>
                <ShieldCheck className="mr-2 h-4 w-4" />
                Ativar 2FA
              </Button>
            )}
          </div>
        )}

        {/* ÔöÇÔöÇ Setup: QR Code + Segredo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
        {etapa === "setup" && (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              1. Abra seu aplicativo autenticador e escaneie o QR code abaixo:
            </p>

            {qrDataUrl ? (
              <div className="flex justify-center rounded-lg border bg-white p-4">
                <img src={qrDataUrl} alt="QR Code 2FA" className="h-48 w-48" />
              </div>
            ) : (
              <div className="flex items-center justify-center rounded-lg border bg-muted/30 p-6">
                <QrCode className="h-12 w-12 text-muted-foreground" />
              </div>
            )}

            <p className="text-sm text-muted-foreground">
              2. Ou insira esta chave manualmente:
            </p>
            <div className="flex items-center gap-2">
              <code className="flex-1 rounded border bg-muted/50 px-3 py-2 text-sm font-mono break-all">
                {segredo}
              </code>
              <Button variant="outline" size="icon" onClick={copiarSegredo}>
                <Copy className="h-4 w-4" />
              </Button>
            </div>

            <p className="text-sm text-muted-foreground">
              3. Digite o c├│digo de 6 d├¡gitos gerado pelo aplicativo:
            </p>
            <div className="flex gap-2">
              <Input
                value={codigo}
                onChange={(e) => setCodigo(e.target.value.replace(/\D/g, "").slice(0, 6))}
                placeholder="000000"
                maxLength={6}
                className="max-w-[200px] font-mono text-lg tracking-widest text-center"
                autoFocus
              />
              <Button onClick={confirmarAtivacao} disabled={processando}>
                {processando ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                ) : null}
                Confirmar
              </Button>
            </div>

            <Button
              variant="ghost"
              size="sm"
              onClick={() => {
                setEtapa("status");
                setCodigo("");
                setErro(null);
              }}
            >
              Cancelar
            </Button>
          </div>
        )}

        {/* ÔöÇÔöÇ Desativar: pedir c├│digo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
        {etapa === "desativar" && (
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Para desativar o 2FA, insira o c├│digo atual do seu aplicativo
              autenticador:
            </p>
            <div className="flex gap-2">
              <Input
                value={codigo}
                onChange={(e) => setCodigo(e.target.value.replace(/\D/g, "").slice(0, 6))}
                placeholder="000000"
                maxLength={6}
                className="max-w-[200px] font-mono text-lg tracking-widest text-center"
                autoFocus
              />
              <Button
                variant="destructive"
                onClick={confirmarDesativacao}
                disabled={processando}
              >
                {processando ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                ) : null}
                Desativar
              </Button>
            </div>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => {
                setEtapa("status");
                setCodigo("");
                setErro(null);
              }}
            >
              Cancelar
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

// ÔöÇÔöÇ QR Code simples via Canvas (sem lib externa) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// Usa API do chart para gerar QR via URL (fallback se n├úo houver lib)
async function gerarQRCodeDataUrl(data: string): Promise<string> {
  // Usa a API p├║blica do QR Server para gerar o QR code
  // Em produ├º├úo, substituir por gera├º├úo local
  const url = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(data)}`;
  const response = await fetch(url);
  const blob = await response.blob();
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
// CotacoesPage ÔÇö Fase 9 ÔÇö Lista de cota├º├Áes com filtros e a├º├Áes
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import { useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { useConfirm } from "@/componentes/ui/confirm-dialog";
import { Card, CardContent } from "@/componentes/ui/card";
import { Button } from "@/componentes/ui/button";
import { Input } from "@/componentes/ui/input";
import { Badge } from "@/componentes/ui/badge";
import { Separator } from "@/componentes/ui/separator";
import {
  Plus,
  Search,
  SendHorizonal,
  Mail,
  MailCheck,
  Clock,
  CheckCircle2,
  XCircle,
  FileText,
  Loader2,
  Users,
  Package,
  ChevronRight,
  AlertCircle,
  Trash2,
} from "lucide-react";
import { useCotacoesPaginadas } from "@/hooks/useCotacoes";
import { NovaCotacaoDrawer } from "./NovaCotacaoDrawer";
import {
  STATUS_COTACAO_LABELS,
  STATUS_COTACAO_CORES,
  excluirCotacao,
} from "@/servicos/cotacoes";
import type { StatusCotacao } from "@/tipos";

const STATUS_ICONS: Record<StatusCotacao, React.ComponentType<{ className?: string }>> = {
  rascunho: FileText,
  enviada: Mail,
  em_resposta: MailCheck,
  encerrada: CheckCircle2,
  cancelada: XCircle,
};

// ÔöÇÔöÇ Formatadores ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function fmtData(d: string) {
  return new Date(d).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });
}

export function CotacoesPage() {
  const navigate = useNavigate();
  const { cotacoes, total, carregando, erro, carregar } = useCotacoesPaginadas();
  const [busca, setBusca] = useState("");
  const [filtroStatus, setFiltroStatus] = useState<StatusCotacao | "">("");
  const [showNova, setShowNova] = useState(false);
  const [pagina, setPagina] = useState(1);

  const recarregar = useCallback(() => {
    carregar(
      { busca: busca || undefined, status: filtroStatus || undefined },
      pagina,
    );
  }, [carregar, busca, filtroStatus, pagina]);

  useEffect(() => { recarregar(); }, [recarregar]);

  const confirmar = useConfirm();

  const handleExcluir = async (id: string) => {
    const ok = await confirmar({
      title: "Excluir cota├º├úo",
      description: "Tem certeza que deseja excluir esta cota├º├úo? Esta a├º├úo n├úo pode ser desfeita.",
      confirmLabel: "Excluir",
      variant: "danger",
    });
    if (!ok) return;
    try {
      await excluirCotacao(id);
      toast.success("Cota├º├úo exclu├¡da com sucesso");
      recarregar();
    } catch {
      toast.error("Erro ao excluir cota├º├úo");
    }
  };

  // ÔöÇÔöÇ Contadores por status ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const cont = {
    rascunho: cotacoes.filter(c => c.status === "rascunho").length,
    enviada: cotacoes.filter(c => c.status === "enviada").length,
    em_resposta: cotacoes.filter(c => c.status === "em_resposta").length,
    encerrada: cotacoes.filter(c => c.status === "encerrada").length,
  };

  return (
    <div className="space-y-6">
      {/* ÔöÇÔöÇ Header ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Cota├º├úo Eletr├┤nica</h2>
          <p className="text-muted-foreground">
            Envio de cota├º├Áes para fornecedores com assinatura eletr├┤nica
          </p>
        </div>
        <Button onClick={() => setShowNova(true)}>
          <Plus className="mr-2 h-4 w-4" />
          Nova Cota├º├úo
        </Button>
      </div>

      {/* ÔöÇÔöÇ Cards resumo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <div className="grid gap-4 md:grid-cols-4">
        {(["rascunho", "enviada", "em_resposta", "encerrada"] as const).map((s) => {
          const Icon = STATUS_ICONS[s];
          return (
            <Card
              key={s}
              className={`cursor-pointer transition hover:shadow-md ${filtroStatus === s ? "ring-2 ring-primary" : ""}`}
              onClick={() => setFiltroStatus(prev => prev === s ? "" : s)}
            >
              <CardContent className="flex items-center gap-3 p-4">
                <div className={`rounded-lg p-2 ${STATUS_COTACAO_CORES[s]}`}>
                  <Icon className="h-5 w-5" />
                </div>
                <div>
                  <p className="text-2xl font-bold">{cont[s]}</p>
                  <p className="text-xs text-muted-foreground">{STATUS_COTACAO_LABELS[s]}</p>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* ÔöÇÔöÇ Filtros ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <div className="flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Buscar cota├º├úo por t├¡tuloÔÇª"
            className="pl-10"
            value={busca}
            onChange={e => { setBusca(e.target.value); setPagina(1); }}
          />
        </div>
        {filtroStatus && (
          <Button variant="ghost" size="sm" onClick={() => setFiltroStatus("")}>
            Limpar filtro
          </Button>
        )}
      </div>

      {/* ÔöÇÔöÇ Lista ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {carregando ? (
        <div className="flex items-center justify-center py-12">
          <Loader2 className="mr-2 h-5 w-5 animate-spin" />
          Carregando cota├º├ÁesÔÇª
        </div>
      ) : erro ? (
        <div className="flex items-center gap-2 rounded-lg border border-red-200 bg-red-50 p-4 text-red-700">
          <AlertCircle className="h-5 w-5" />
          {erro}
        </div>
      ) : cotacoes.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12 text-center">
            <SendHorizonal className="mb-4 h-12 w-12 text-muted-foreground/40" />
            <h3 className="text-lg font-medium">Nenhuma cota├º├úo encontrada</h3>
            <p className="mt-1 text-sm text-muted-foreground">
              Crie uma nova cota├º├úo para enviar para fornecedores.
            </p>
            <Button className="mt-4" onClick={() => setShowNova(true)}>
              <Plus className="mr-2 h-4 w-4" />
              Criar Primeira Cota├º├úo
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {cotacoes.map((c) => {
            const Icon = STATUS_ICONS[c.status];
            const encerrada = new Date(c.data_encerramento) < new Date();
            const fornCount = (c as any).fornecedores?.length ?? 0;
            const itemCount = (c as any).itens?.length ?? 0;
            return (
              <Card
                key={c.id}
                className="cursor-pointer transition hover:shadow-md"
                onClick={() => navigate(`/cotacoes/${c.id}`)}
              >
                <CardContent className="flex items-center gap-4 p-4">
                  {/* ├ìcone status */}
                  <div className={`rounded-lg p-2 ${STATUS_COTACAO_CORES[c.status]}`}>
                    <Icon className="h-5 w-5" />
                  </div>

                  {/* Info principal */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="font-semibold truncate">{c.titulo}</span>
                      <Badge variant="outline" className={STATUS_COTACAO_CORES[c.status]}>
                        {STATUS_COTACAO_LABELS[c.status]}
                      </Badge>
                      {encerrada && c.status !== "encerrada" && c.status !== "cancelada" && (
                        <Badge variant="destructive" className="text-xs">Prazo vencido</Badge>
                      )}
                    </div>
                    <div className="mt-1 flex items-center gap-4 text-xs text-muted-foreground">
                      <span className="flex items-center gap-1">
                        <Clock className="h-3 w-3" />
                        {fmtData(c.data_abertura)} ÔåÆ {fmtData(c.data_encerramento)}
                      </span>
                      {(c as any).cesta && (
                        <span className="flex items-center gap-1 truncate max-w-[200px]">
                          <Package className="h-3 w-3" />
                          {(c as any).cesta.descricao_objeto}
                        </span>
                      )}
                    </div>
                  </div>

                  {/* M├®tricas r├ípidas */}
                  <div className="hidden gap-6 text-center text-xs text-muted-foreground md:flex">
                    <div>
                      <Package className="mx-auto mb-1 h-4 w-4" />
                      <span className="font-medium">{itemCount}</span>
                      <p>Itens</p>
                    </div>
                    <div>
                      <Users className="mx-auto mb-1 h-4 w-4" />
                      <span className="font-medium">{fornCount}</span>
                      <p>Fornecedores</p>
                    </div>
                  </div>

                  {/* A├º├Áes */}
                  <div className="flex items-center gap-1">
                    {c.status === "rascunho" && (
                      <Button
                        size="icon"
                        variant="ghost"
                        className="h-8 w-8 text-destructive"
                        onClick={(e) => { e.stopPropagation(); handleExcluir(c.id); }}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    )}
                    <ChevronRight className="h-5 w-5 text-muted-foreground" />
                  </div>
                </CardContent>
              </Card>
            );
          })}

          <Separator />

          {/* Pagina├º├úo */}
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
              {total} cota├º├úo(├Áes) encontrada(s)
            </p>
            <div className="flex gap-2">
              <Button
                size="sm"
                variant="outline"
                disabled={pagina === 1}
                onClick={() => setPagina(p => p - 1)}
              >
                Anterior
              </Button>
              <Button
                size="sm"
                variant="outline"
                disabled={cotacoes.length < 20}
                onClick={() => setPagina(p => p + 1)}
              >
                Pr├│xima
              </Button>
            </div>
          </div>
        </div>
      )}

      {/* ÔöÇÔöÇ Drawer Nova Cota├º├úo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {showNova && (
        <NovaCotacaoDrawer
          aberto={showNova}
          onClose={() => setShowNova(false)}
          onCriada={(cotacao: { id: string }) => {
            setShowNova(false);
            navigate(`/cotacoes/${cotacao.id}`);
          }}
        />
      )}
    </div>
  );
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
// DetalheCotacaoPage ÔÇö Fase 9
// Visualiza├º├úo completa da cota├º├úo: cabe├ºalho, itens, fornecedores, respostas,
// lan├ºamentos manuais e transfer├¬ncia para cesta
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import { useCallback, useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "sonner";
import { useConfirm } from "@/componentes/ui/confirm-dialog";
import { Card, CardContent } from "@/componentes/ui/card";
import { Button } from "@/componentes/ui/button";
import { Input } from "@/componentes/ui/input";
import { Badge } from "@/componentes/ui/badge";
import { Separator } from "@/componentes/ui/separator";
import {
  ArrowLeft,
  ArrowUpRight,
  Check,
  CheckCircle2,
  Clock,
  Link2,
  Loader2,
  Mail,
  MailCheck,
  Package,
  Pencil,
  Plus,
  SendHorizonal,
  Trash2,
  Users,
  XCircle,
  AlertCircle,
  FileText,
  Phone,
  MessageSquare,
  User,
  ExternalLink,
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useCotacaoDetalhe } from "@/hooks/useCotacoes";
import {
  STATUS_COTACAO_LABELS,
  STATUS_COTACAO_CORES,
  MEIO_LABELS,
  gerarLinkPortal,
  adicionarFornecedorCotacao,
  removerFornecedorCotacao,
} from "@/servicos/cotacoes";
import type {
  StatusCotacao,
  RespostaCotacao,
  MeioRecebimento,
} from "@/tipos";

// ÔöÇÔöÇ Formatadores ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function fmtData(d: string) {
  return new Date(d).toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric" });
}
function fmtDataHora(d: string) {
  return new Date(d).toLocaleString("pt-BR", { day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" });
}
function fmtMoeda(v: number) {
  return v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

const STATUS_ICONS: Record<StatusCotacao, React.ComponentType<{ className?: string }>> = {
  rascunho: FileText,
  enviada: Mail,
  em_resposta: MailCheck,
  encerrada: CheckCircle2,
  cancelada: XCircle,
};

const MEIO_ICONS: Record<MeioRecebimento, React.ComponentType<{ className?: string }>> = {
  email: Mail,
  whatsapp: MessageSquare,
  telefone: Phone,
  presencial: User,
  manual: Pencil,
};

type Aba = "resumo" | "fornecedores" | "respostas" | "lancamentos";

export function DetalheCotacaoPage() {
  const { cotacaoId } = useParams<{ cotacaoId: string }>();
  const navigate = useNavigate();
  const { servidor } = useAuth();
  const confirmar = useConfirm();
  const {
    cotacao,
    respostas,
    lancamentos,
    carregando,
    erro,
    carregar,
    enviar,
    alterarStatus,
    excluir,
    transferirResposta,
    lancarManual,
    transferirLancamento,
  } = useCotacaoDetalhe();

  const [aba, setAba] = useState<Aba>("resumo");
  const [copiado, setCopiado] = useState<string | null>(null);

  // Lan├ºamento manual state
  const [showLancamento, setShowLancamento] = useState(false);
  const [lancForm, setLancForm] = useState({
    item_cesta_id: "",
    razao_social: "",
    cpf_cnpj: "",
    email: "",
    telefone: "",
    marca: "",
    valor_unitario: "",
    observacoes: "",
    registro_anvisa: "",
    meio_recebimento: "manual" as MeioRecebimento,
  });

  // Adicionar fornecedor avulso
  const [showAddForn, setShowAddForn] = useState(false);
  const [novoForn, setNovoForn] = useState({ razao_social: "", cpf_cnpj: "", email: "", telefone: "" });

  const recarregar = useCallback(() => {
    if (cotacaoId) carregar(cotacaoId);
  }, [cotacaoId, carregar]);

  useEffect(() => { recarregar(); }, [recarregar]);

  if (carregando && !cotacao) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="mr-2 h-6 w-6 animate-spin" />
        Carregando cota├º├úoÔÇª
      </div>
    );
  }

  if (erro && !cotacao) {
    return (
      <div className="flex flex-col items-center justify-center py-20 text-center">
        <AlertCircle className="mb-4 h-10 w-10 text-red-400" />
        <p className="text-lg font-medium">Erro ao carregar cota├º├úo</p>
        <p className="text-sm text-muted-foreground">{erro}</p>
        <Button variant="outline" className="mt-4" onClick={() => navigate("/cotacoes")}>
          <ArrowLeft className="mr-1 h-4 w-4" /> Voltar
        </Button>
      </div>
    );
  }

  if (!cotacao) return null;

  const StatusIcon = STATUS_ICONS[cotacao.status];
  const encerrada = new Date(cotacao.data_encerramento) < new Date();
  const isRascunho = cotacao.status === "rascunho";
  const isEnviada = cotacao.status === "enviada" || cotacao.status === "em_resposta";
  const fornecedores = cotacao.fornecedores ?? [];
  const itens = cotacao.itens ?? [];

  // Agrupar respostas por fornecedor
  const respostasPorFornecedor = new Map<string, RespostaCotacao[]>();
  for (const r of respostas) {
    const key = r.cotacao_fornecedor_id;
    if (!respostasPorFornecedor.has(key)) respostasPorFornecedor.set(key, []);
    respostasPorFornecedor.get(key)!.push(r);
  }

  const copiarLink = async (token: string) => {
    const link = gerarLinkPortal(token);
    await navigator.clipboard.writeText(link);
    setCopiado(token);
    setTimeout(() => setCopiado(null), 2000);
  };

  const handleEnviar = async () => {
    if (!confirm("Enviar cota├º├úo para todos os fornecedores?")) return;
    await enviar(cotacao.id);
    recarregar();
  };

  const handleEncerrar = async () => {
    if (!confirm("Encerrar esta cota├º├úo?")) return;
    await alterarStatus(cotacao.id, "encerrada");
    recarregar();
  };

  const handleCancelar = async () => {
    if (!confirm("Cancelar esta cota├º├úo?")) return;
    await alterarStatus(cotacao.id, "cancelada");
    recarregar();
  };

  const handleExcluir = async () => {
    if (!confirm("Excluir esta cota├º├úo?")) return;
    await excluir(cotacao.id);
    navigate("/cotacoes");
  };

  const handleTransferir = async (respostaId: string) => {
    if (!servidor) return;
    if (!confirm("Transferir este pre├ºo para a cesta?")) return;
    await transferirResposta(respostaId, servidor.id);
    recarregar();
  };

  const handleLancarManual = async () => {
    if (!servidor || !lancForm.item_cesta_id || !lancForm.razao_social || !lancForm.valor_unitario) return;
    await lancarManual(cotacao.id, {
      item_cesta_id: lancForm.item_cesta_id,
      razao_social: lancForm.razao_social,
      cpf_cnpj: lancForm.cpf_cnpj || undefined,
      email: lancForm.email || undefined,
      telefone: lancForm.telefone || undefined,
      marca: lancForm.marca || undefined,
      valor_unitario: parseFloat(lancForm.valor_unitario),
      observacoes: lancForm.observacoes || undefined,
      registro_anvisa: lancForm.registro_anvisa || undefined,
      meio_recebimento: lancForm.meio_recebimento,
      lancado_por: servidor.id,
    });
    setLancForm({
      item_cesta_id: "",
      razao_social: "",
      cpf_cnpj: "",
      email: "",
      telefone: "",
      marca: "",
      valor_unitario: "",
      observacoes: "",
      registro_anvisa: "",
      meio_recebimento: "manual",
    });
    setShowLancamento(false);
    recarregar();
  };

  const handleTransferirLancamento = async (lancamentoId: string) => {
    if (!servidor) return;
    if (!confirm("Transferir este lan├ºamento para a cesta?")) return;
    await transferirLancamento(lancamentoId, servidor.id);
    recarregar();
  };

  const handleAddFornecedor = async () => {
    if (!novoForn.razao_social || !novoForn.email) return;
    try {
      await adicionarFornecedorCotacao(cotacao.id, {
        razao_social: novoForn.razao_social,
        cpf_cnpj: novoForn.cpf_cnpj || undefined,
        email: novoForn.email,
        telefone: novoForn.telefone || undefined,
      }, cotacao.data_encerramento);
      setNovoForn({ razao_social: "", cpf_cnpj: "", email: "", telefone: "" });
      setShowAddForn(false);
      toast.success("Fornecedor adicionado com sucesso");
      recarregar();
    } catch {
      toast.error("Erro ao adicionar fornecedor");
    }
  };

  const handleRemoverFornecedor = async (fornId: string) => {
    const ok = await confirmar({
      title: "Remover fornecedor",
      description: "Tem certeza que deseja remover este fornecedor da cota├º├úo?",
      confirmLabel: "Remover",
      variant: "danger",
    });
    if (!ok) return;
    try {
      await removerFornecedorCotacao(fornId);
      toast.success("Fornecedor removido");
      recarregar();
    } catch {
      toast.error("Erro ao remover fornecedor");
    }
  };

  return (
    <div className="space-y-6">
      {/* ÔöÇÔöÇ Header ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <div className="flex items-start justify-between">
        <div className="flex items-start gap-4">
          <Button variant="ghost" size="icon" onClick={() => navigate("/cotacoes")}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <div className="flex items-center gap-3">
              <h2 className="text-2xl font-bold">{cotacao.titulo}</h2>
              <Badge className={STATUS_COTACAO_CORES[cotacao.status]}>
                <StatusIcon className="mr-1 h-3 w-3" />
                {STATUS_COTACAO_LABELS[cotacao.status]}
              </Badge>
              {encerrada && isEnviada && (
                <Badge variant="destructive">Prazo vencido</Badge>
              )}
            </div>
            <p className="mt-1 text-sm text-muted-foreground">
              Cota├º├úo #{cotacao.numero} ÔÇö {fmtData(cotacao.data_abertura)} ÔåÆ {fmtData(cotacao.data_encerramento)}
              {cotacao.descricao && ` ÔÇö ${cotacao.descricao}`}
            </p>
          </div>
        </div>

        {/* A├º├Áes */}
        <div className="flex gap-2">
          {isRascunho && (
            <>
              <Button size="sm" onClick={handleEnviar}>
                <SendHorizonal className="mr-1 h-4 w-4" /> Enviar
              </Button>
              <Button size="sm" variant="destructive" onClick={handleExcluir}>
                <Trash2 className="mr-1 h-4 w-4" /> Excluir
              </Button>
            </>
          )}
          {isEnviada && (
            <Button size="sm" variant="outline" onClick={handleEncerrar}>
              <CheckCircle2 className="mr-1 h-4 w-4" /> Encerrar
            </Button>
          )}
          {(isRascunho || isEnviada) && (
            <Button size="sm" variant="ghost" onClick={handleCancelar}>
              <XCircle className="mr-1 h-4 w-4" /> Cancelar
            </Button>
          )}
        </div>
      </div>

      {/* ÔöÇÔöÇ Abas ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      <div className="flex gap-1 border-b">
        {(["resumo", "fornecedores", "respostas", "lancamentos"] as Aba[]).map((a) => (
          <button
            key={a}
            className={`px-4 py-2 text-sm font-medium border-b-2 transition ${
              aba === a ? "border-primary text-primary" : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
            onClick={() => setAba(a)}
          >
            {a === "resumo" ? "Resumo" : a === "fornecedores" ? `Fornecedores (${fornecedores.length})` : a === "respostas" ? `Respostas (${respostas.length})` : `Lan├ºamentos (${lancamentos.length})`}
          </button>
        ))}
      </div>

      {/* ÔöÇÔöÇ ABA: Resumo ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {aba === "resumo" && (
        <div className="grid gap-6 md:grid-cols-2">
          {/* Itens da cota├º├úo */}
          <Card>
            <CardContent className="p-4">
              <h3 className="mb-3 flex items-center gap-2 font-semibold">
                <Package className="h-4 w-4" />
                Itens ({itens.length})
              </h3>
              {itens.length === 0 ? (
                <p className="text-sm text-muted-foreground">Nenhum item na cota├º├úo</p>
              ) : (
                <div className="space-y-2 max-h-[300px] overflow-y-auto">
                  {itens.map((it, idx) => {
                    const prod = it.item_cesta?.produto;
                    return (
                      <div key={it.id} className="flex items-center gap-2 rounded border p-2 text-sm">
                        <span className="text-xs font-medium text-muted-foreground w-6">{idx + 1}.</span>
                        <div className="flex-1 min-w-0">
                          <p className="truncate font-medium">{prod?.descricao ?? "Item"}</p>
                          <p className="text-xs text-muted-foreground">
                            Qtd: {it.quantidade} {it.unidade ?? prod?.unidade_medida?.sigla ?? ""}
                          </p>
                        </div>
                        {it.exige_anvisa && (
                          <Badge variant="outline" className="text-[10px] bg-purple-50 text-purple-700">ANVISA</Badge>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>

          {/* M├®tricas */}
          <div className="space-y-4">
            <Card>
              <CardContent className="grid grid-cols-2 gap-4 p-4">
                <div>
                  <p className="text-xs text-muted-foreground">Fornecedores</p>
                  <p className="text-2xl font-bold">{fornecedores.length}</p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Responderam</p>
                  <p className="text-2xl font-bold">
                    {respostasPorFornecedor.size}
                  </p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Respostas</p>
                  <p className="text-2xl font-bold">{respostas.length}</p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground">Lan├º. Manuais</p>
                  <p className="text-2xl font-bold">{lancamentos.length}</p>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-4 text-sm space-y-2">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Cesta vinculada</span>
                  <span className="font-medium truncate max-w-[200px]">
                    {(cotacao as any).cesta?.descricao_objeto ?? "ÔÇö"}
                  </span>
                </div>
                <Separator />
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Criado por</span>
                  <span className="font-medium">
                    {(cotacao as any).criado_por_servidor?.nome ?? "ÔÇö"}
                  </span>
                </div>
                <Separator />
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Criado em</span>
                  <span>{fmtDataHora(cotacao.criado_em)}</span>
                </div>
              </CardContent>
            </Card>
          </div>
        </div>
      )}

      {/* ÔöÇÔöÇ ABA: Fornecedores ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {aba === "fornecedores" && (
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
              Fornecedores convidados para esta cota├º├úo
            </p>
            {isRascunho && (
              <Button size="sm" variant="outline" onClick={() => setShowAddForn(true)}>
                <Plus className="mr-1 h-4 w-4" /> Adicionar Fornecedor
              </Button>
            )}
          </div>

          {/* Formul├írio novo fornecedor */}
          {showAddForn && (
            <Card>
              <CardContent className="p-4 space-y-3">
                <h4 className="text-sm font-medium">Novo Fornecedor</h4>
                <div className="grid gap-3 grid-cols-2">
                  <Input placeholder="Raz├úo Social *" value={novoForn.razao_social} onChange={e => setNovoForn(p => ({ ...p, razao_social: e.target.value }))} />
                  <Input placeholder="E-mail *" type="email" value={novoForn.email} onChange={e => setNovoForn(p => ({ ...p, email: e.target.value }))} />
                  <Input placeholder="CPF/CNPJ" value={novoForn.cpf_cnpj} onChange={e => setNovoForn(p => ({ ...p, cpf_cnpj: e.target.value }))} />
                  <Input placeholder="Telefone" value={novoForn.telefone} onChange={e => setNovoForn(p => ({ ...p, telefone: e.target.value }))} />
                </div>
                <div className="flex justify-end gap-2">
                  <Button size="sm" variant="ghost" onClick={() => setShowAddForn(false)}>Cancelar</Button>
                  <Button size="sm" onClick={handleAddFornecedor} disabled={!novoForn.razao_social || !novoForn.email}>
                    <Plus className="mr-1 h-4 w-4" /> Adicionar
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}

          {fornecedores.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center py-8 text-center">
                <Users className="mb-3 h-10 w-10 text-muted-foreground/40" />
                <p className="text-sm text-muted-foreground">Nenhum fornecedor convidado</p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-2">
              {fornecedores.map((f) => {
                const resps = respostasPorFornecedor.get(f.id) ?? [];
                const temRespostas = resps.length > 0;
                return (
                  <Card key={f.id}>
                    <CardContent className="flex items-center gap-4 p-4">
                      <div className={`rounded-full p-2 ${temRespostas ? "bg-green-100" : f.acessou_portal ? "bg-amber-100" : f.email_enviado ? "bg-blue-100" : "bg-gray-100"}`}>
                        {temRespostas ? <CheckCircle2 className="h-4 w-4 text-green-700" /> :
                         f.acessou_portal ? <ExternalLink className="h-4 w-4 text-amber-700" /> :
                         f.email_enviado ? <Mail className="h-4 w-4 text-blue-700" /> :
                         <Clock className="h-4 w-4 text-gray-500" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="font-medium">{f.razao_social}</p>
                        <div className="flex gap-3 text-xs text-muted-foreground mt-0.5">
                          <span>{f.email}</span>
                          {f.cpf_cnpj && <span>{f.cpf_cnpj}</span>}
                        </div>
                        <div className="flex gap-2 mt-1">
                          {f.email_enviado && (
                            <Badge variant="outline" className="text-[10px] bg-blue-50">
                              E-mail enviado {f.email_enviado_em ? fmtDataHora(f.email_enviado_em) : ""}
                            </Badge>
                          )}
                          {f.acessou_portal && (
                            <Badge variant="outline" className="text-[10px] bg-amber-50">
                              Acessou portal {f.acessou_em ? fmtDataHora(f.acessou_em) : ""}
                            </Badge>
                          )}
                          {temRespostas && (
                            <Badge variant="outline" className="text-[10px] bg-green-50">
                              {resps.length} resposta(s)
                            </Badge>
                          )}
                        </div>
                      </div>
                      <div className="flex items-center gap-1">
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => copiarLink(f.token_acesso)}
                          title="Copiar link do portal"
                        >
                          {copiado === f.token_acesso ? <Check className="h-4 w-4 text-green-600" /> : <Link2 className="h-4 w-4" />}
                        </Button>
                        {isRascunho && (
                          <Button
                            size="icon"
                            variant="ghost"
                            className="h-8 w-8 text-destructive"
                            onClick={() => handleRemoverFornecedor(f.id)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* ÔöÇÔöÇ ABA: Respostas ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {aba === "respostas" && (
        <div className="space-y-4">
          {respostas.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center py-8 text-center">
                <MailCheck className="mb-3 h-10 w-10 text-muted-foreground/40" />
                <p className="text-sm text-muted-foreground">
                  Nenhuma resposta recebida ainda
                </p>
              </CardContent>
            </Card>
          ) : (
            <>
              {/* Tabela de respostas */}
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b text-left text-xs text-muted-foreground">
                      <th className="p-2">Fornecedor</th>
                      <th className="p-2">Item</th>
                      <th className="p-2">Marca</th>
                      <th className="p-2 text-right">Valor Unit.</th>
                      <th className="p-2">ANVISA</th>
                      <th className="p-2">Data</th>
                      <th className="p-2">Status</th>
                      <th className="p-2"></th>
                    </tr>
                  </thead>
                  <tbody>
                    {respostas.map((r) => {
                      const forn = fornecedores.find(f => f.id === r.cotacao_fornecedor_id);
                      const item = itens.find(i => i.id === r.cotacao_item_id);
                      const prod = item?.item_cesta?.produto;
                      return (
                        <tr key={r.id} className="border-b hover:bg-muted/50">
                          <td className="p-2 font-medium max-w-[150px] truncate">
                            {(r as any).cotacao_fornecedor?.razao_social ?? forn?.razao_social ?? "ÔÇö"}
                          </td>
                          <td className="p-2 max-w-[200px] truncate">
                            {prod?.descricao ?? (r as any).cotacao_item?.item_cesta?.produto?.descricao ?? "ÔÇö"}
                          </td>
                          <td className="p-2">{r.marca ?? "ÔÇö"}</td>
                          <td className="p-2 text-right font-mono">{fmtMoeda(r.valor_unitario)}</td>
                          <td className="p-2">
                            {r.registro_anvisa ? (
                              <Badge variant="outline" className="text-[10px] bg-purple-50 text-purple-700">
                                {r.registro_anvisa}
                              </Badge>
                            ) : "ÔÇö"}
                          </td>
                          <td className="p-2 text-xs">{fmtDataHora(r.respondido_em)}</td>
                          <td className="p-2">
                            {r.transferido_cesta ? (
                              <Badge className="bg-green-100 text-green-700 text-[10px]">
                                <Check className="mr-0.5 h-3 w-3" /> Transferido
                              </Badge>
                            ) : (
                              <Badge variant="outline" className="text-[10px]">Pendente</Badge>
                            )}
                          </td>
                          <td className="p-2">
                            {!r.transferido_cesta && (
                              <Button
                                size="sm"
                                variant="outline"
                                onClick={() => handleTransferir(r.id)}
                              >
                                <ArrowUpRight className="mr-1 h-3 w-3" /> Transferir
                              </Button>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </>
          )}
        </div>
      )}

      {/* ÔöÇÔöÇ ABA: Lan├ºamentos Manuais ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
      {aba === "lancamentos" && (
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
