                        {c.numero_contrato}
                      </button>
                    </td>
                    <td className="px-4 py-3">
                      <div className="font-medium">{c.municipio_nome || "ÔÇö"}</div>
                      <div className="text-xs text-muted-foreground">{c.municipio_uf || ""}</div>
