// Configura├º├úo Firebase + service worker para notifica├º├Áes push
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
import { api } from "@/lib/api";

// ÔöÇÔöÇ Configura├º├úo Firebase (importa├º├úo din├ómica) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
let messaging: import("firebase/messaging").Messaging | null = null;

async function getMessaging() {
  if (messaging) return messaging;
  const { initializeApp } = await import("firebase/app");
  const { getMessaging: getMsg, isSupported } = await import("firebase/messaging");

  const supported = await isSupported();
  if (!supported) return null;

  const app = initializeApp({
    apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
    authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
    projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
    storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
    messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
    appId: import.meta.env.VITE_FIREBASE_APP_ID,
  });

  messaging = getMsg(app);
  return messaging;
}

// ÔöÇÔöÇ Solicitar permiss├úo e obter token FCM ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export async function solicitarPermissaoNotificacao(): Promise<string | null> {
  try {
    const permission = await Notification.requestPermission();
    if (permission !== "granted") return null;

    const msg = await getMessaging();
    if (!msg) return null;

    const { getToken } = await import("firebase/messaging");
    const token = await getToken(msg, {
      vapidKey: import.meta.env.VITE_FIREBASE_VAPID_KEY,
    });

    // Salvar token na API para envio server-side
    if (token) {
      await salvarTokenDispositivo(token);
    }

    return token;
  } catch (error) {
    console.error("[FCM] Erro ao solicitar permiss├úo:", error);
    return null;
  }
}

// ÔöÇÔöÇ Ouvir mensagens em foreground ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export async function ouvirNotificacoesForeground(
  callback: (payload: { title: string; body: string; data?: Record<string, string> }) => void,
): Promise<(() => void) | null> {
  const msg = await getMessaging();
  if (!msg) return null;

  const { onMessage } = await import("firebase/messaging");
  const unsubscribe = onMessage(msg, (payload) => {
    callback({
      title: payload.notification?.title ?? "Nova notifica├º├úo",
      body: payload.notification?.body ?? "",
      data: payload.data,
    });
  });

  return unsubscribe;
}

// ÔöÇÔöÇ Salvar token do dispositivo na API ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
async function salvarTokenDispositivo(token: string): Promise<void> {
  await api.post("/api/notificacoes/registrar", {
    token_fcm: token,
    plataforma: detectarPlataforma(),
  });
}

// ÔöÇÔöÇ Remover token (logout) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export async function removerTokenDispositivo(): Promise<void> {
  const msg = await getMessaging();
  if (!msg) return;

  const { deleteToken } = await import("firebase/messaging");
  await deleteToken(msg);
}

// ÔöÇÔöÇ Helper ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function detectarPlataforma(): string {
  const ua = navigator.userAgent;
  if (/android/i.test(ua)) return "android";
  if (/iPad|iPhone|iPod/.test(ua)) return "ios";
  return "web";
}

