function renderRota(
  props: Record<string, any> = {},
  initialEntries = ["/protegido"],
) {
  return render(
    createElement(
      MemoryRouter,
      { initialEntries },
      createElement(
        Routes,
        null,
        createElement(Route, {
          path: "/protegido",
          element: createElement(PrivateRoute, props, createElement("div", null, "Conte├║do protegido")),
        }),
        createElement(Route, {
          path: "/login",
          element: createElement("div", null, "P├ígina de login"),
        }),
        createElement(Route, {
          path: "/",
          element: createElement("div", null, "P├ígina inicial"),
        }),
      ),
    ),
  );
}

describe("PrivateRoute", () => {
  it("mostra loading spinner enquanto carrega", () => {
    mockUseAuth.mockReturnValue({
      usuario: null,
      servidor: null,
      perfil: null,
      carregando: true,
    });

    renderRota();
    expect(screen.getByText("Carregando...")).toBeInTheDocument();
  });

  it("redireciona para /login quando n├úo autenticado", () => {
    mockUseAuth.mockReturnValue({
      usuario: null,
      servidor: null,
      perfil: null,
      carregando: false,
    });

    renderRota();
    expect(screen.getByText("P├ígina de login")).toBeInTheDocument();
    expect(screen.queryByText("Conte├║do protegido")).not.toBeInTheDocument();
  });

  it("mostra loading de permiss├Áes quando autenticado mas sem servidor", () => {
    mockUseAuth.mockReturnValue({
      usuario: { uid: "u1" },
      servidor: null,
      perfil: null,
      carregando: false,
    });

    renderRota();
    expect(screen.getByText("Verificando permiss├Áes...")).toBeInTheDocument();
  });

  it("renderiza children quando autenticado com servidor", () => {
    mockUseAuth.mockReturnValue({
      usuario: { uid: "u1" },
      servidor: { id: "s1", nome: "Servidor" },
      perfil: "administrador",
      carregando: false,
    });

    renderRota();
    expect(screen.getByText("Conte├║do protegido")).toBeInTheDocument();
  });

  it("bloqueia acesso quando perfil n├úo ├® permitido", () => {
    mockUseAuth.mockReturnValue({
      usuario: { uid: "u1" },
      servidor: { id: "s1", nome: "Servidor" },
      perfil: "pesquisador",
      carregando: false,
    });

    renderRota({ perfisPermitidos: ["administrador"] });
    expect(screen.queryByText("Conte├║do protegido")).not.toBeInTheDocument();
    expect(screen.getByText("P├ígina inicial")).toBeInTheDocument();
  });

  it("permite acesso quando perfil est├í na lista", () => {
    mockUseAuth.mockReturnValue({
      usuario: { uid: "u1" },
      servidor: { id: "s1", nome: "Servidor" },
      perfil: "gestor",
      carregando: false,
    });

    renderRota({ perfisPermitidos: ["administrador", "gestor"] });
    expect(screen.getByText("Conte├║do protegido")).toBeInTheDocument();
  });

  it("permite qualquer perfil quando perfisPermitidos n├úo ├® informado", () => {
    mockUseAuth.mockReturnValue({
      usuario: { uid: "u1" },
      servidor: { id: "s1", nome: "Servidor" },
      perfil: "pesquisador",
      carregando: false,
    });

    renderRota();
    expect(screen.getByText("Conte├║do protegido")).toBeInTheDocument();
  });
});

